insert into bank_questions (question_key, page_id, page_name, source, qtype, marks, snapshot, answer_key)
values
('5-2-sources-of-finance:mcq:e921db70', '5-2-sources-of-finance', '5.2 Sources of Finance', 'mcq', 'mcq', 1, '{"question": "Which of the following is an advantage of receiving trade credit?", "options": ["It can be used to pay wages and salaries", "It encourages production operatives to work harder", "It is often interest free", "It may bring new skills into the business"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: C. Trade credit is typically interest-free within the agreed credit period (e.g. 30–90 days). A is wrong — trade credit is for goods, not wages. B is unrelated to finance. D describes a benefit of taking on a new partner, not trade credit."}'::jsonb),
('5-2-sources-of-finance:mcq:73f5361d', '5-2-sources-of-finance', '5.2 Sources of Finance', 'mcq', 'mcq', 1, '{"question": "Which of the following is a benefit to a public limited company of using a share issue to raise finance?", "options": ["Dividends will need to be paid", "New skills will be brought into the company", "No interest will be paid", "Repayments will be spread over a long period of time"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: C. A key benefit of issuing shares is that no interest is payable, unlike a loan. A is a disadvantage (dividends are a cost). B can happen but is not guaranteed. D describes a bank loan, not a share issue — shares do not have repayments."}'::jsonb),
('5-2-sources-of-finance:mcq:0d21763a', '5-2-sources-of-finance', '5.2 Sources of Finance', 'mcq', 'mcq', 1, '{"question": "Which of the following is NOT a good source of new capital (raising additional funds)?", "options": ["Taking a new partner", "Overdraft", "Share issue", "Crowdfunding"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B — Overdraft. An overdraft is a short-term borrowing tool for managing cash flow; it is not a source of new, permanent capital. Taking a new partner, issuing shares and crowdfunding all bring in new capital to the business."}'::jsonb),
('5-2-sources-of-finance:mcq:0f8ca026', '5-2-sources-of-finance', '5.2 Sources of Finance', 'mcq', 'mcq', 1, '{"question": "A business has decided to update all of its computers and printers. This decision will:", "options": ["Increase selling prices", "Reduce fixed costs", "Require financial resources", "Temporarily increase cash inflows"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: C. Buying computers and printers is a capital expenditure — it requires financial resources (money). It will not automatically increase selling prices or reduce fixed costs (it may actually increase them). It will temporarily decrease cash inflows (or increase outflows), not increase them."}'::jsonb),
('5-2-sources-of-finance:mcq:a72bf5c0', '5-2-sources-of-finance', '5.2 Sources of Finance', 'mcq', 'mcq', 1, '{"question": "Which of the following is an appropriate source of finance for a newly established company?", "options": ["Overdraft", "Retained profit", "Sale of assets", "Taking a partner"]}'::jsonb, '{"answer": 0, "explain": "Correct answer: A — Overdraft. An overdraft is available to new businesses and helps cover short-term cash flow gaps. Retained profit (B) and sale of assets (C) are only available to established businesses that have already traded. Taking a partner (D) is possible but less common for newly established companies."}'::jsonb),
('5-2-sources-of-finance:mcq:9553ae92', '5-2-sources-of-finance', '5.2 Sources of Finance', 'mcq', 'mcq', 1, '{"question": "A sole trader is short of cash to pay a supplier this month. She should:", "options": ["Buy higher quality products", "Improve customer service", "Get an overdraft", "Repay her loan"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: C — Get an overdraft. An overdraft is the ideal short-term solution for a temporary cash flow problem, allowing the business to continue trading. Buying higher quality products or improving customer service will not solve the immediate cash shortage. Repaying a loan would make the cash problem worse."}'::jsonb),
('5-2-sources-of-finance:mcq:2fa383c1', '5-2-sources-of-finance', '5.2 Sources of Finance', 'mcq', 'mcq', 1, '{"question": "Which of the following is a short-term source of finance suitable for a new business?", "options": ["Retained profit", "Sale of business assets", "Share issue", "Trade credit"]}'::jsonb, '{"answer": 3, "explain": "Correct answer: D — Trade credit. Trade credit allows a new business to obtain goods from a supplier without paying immediately, which is ideal for a short-term cash need. Retained profit (A) and sale of assets (B) require the business to have been trading. A share issue (C) is long-term and requires incorporation as a limited company."}'::jsonb),
('5-2-sources-of-finance:tf:af218c09', '5-2-sources-of-finance', '5.2 Sources of Finance', 'tf', 'tf', 1, '{"question": "A bank loan must be repaid with interest."}'::jsonb, '{"answer": true, "explain": "TRUE. A bank loan is a form of external borrowing. The lender charges interest on the amount borrowed, which must be repaid in addition to the original loan amount."}'::jsonb),
('5-2-sources-of-finance:tf:fd43ef93', '5-2-sources-of-finance', '5.2 Sources of Finance', 'tf', 'tf', 1, '{"question": "Shareholders are part-owners of a business."}'::jsonb, '{"answer": true, "explain": "TRUE. When investors buy shares in a company, they become part-owners (shareholders). They are entitled to vote on key decisions and may receive dividends from profits."}'::jsonb),
('5-2-sources-of-finance:tf:b71d0a17', '5-2-sources-of-finance', '5.2 Sources of Finance', 'tf', 'tf', 1, '{"question": "Banks will always lend money to a business that applies for a loan."}'::jsonb, '{"answer": false, "explain": "FALSE. Banks assess the risk of lending. Businesses with a poor financial record, insufficient security, or operating in a very risky sector may be refused a loan."}'::jsonb),
('5-2-sources-of-finance:tf:56814ee9', '5-2-sources-of-finance', '5.2 Sources of Finance', 'tf', 'tf', 1, '{"question": "Retained profit is available to both new and established businesses."}'::jsonb, '{"answer": false, "explain": "FALSE. Retained profit is only available to established businesses that have already traded and made a profit. A new business has not yet generated any profit to retain."}'::jsonb),
('5-2-sources-of-finance:tf:323484c6', '5-2-sources-of-finance', '5.2 Sources of Finance', 'tf', 'tf', 1, '{"question": "An overdraft is a cheap and appropriate way for a business to fund the purchase of a new building."}'::jsonb, '{"answer": false, "explain": "FALSE. An overdraft is a short-term source of finance suitable for day-to-day cash flow issues. Buying a building requires long-term finance (e.g. a bank loan). Using an overdraft long-term is very expensive due to high daily interest charges."}'::jsonb),
('5-2-sources-of-finance:tf:7b1c36e9', '5-2-sources-of-finance', '5.2 Sources of Finance', 'tf', 'tf', 1, '{"question": "Trade credit is typically interest-free if paid within the agreed time limit."}'::jsonb, '{"answer": true, "explain": "TRUE. Trade credit allows a business to receive goods and pay for them later, usually within 30–90 days, without paying interest — as long as payment is made within the agreed period."}'::jsonb),
('5-2-sources-of-finance:tf:accf3f15', '5-2-sources-of-finance', '5.2 Sources of Finance', 'tf', 'tf', 1, '{"question": "Sole traders are able to raise finance by issuing shares."}'::jsonb, '{"answer": false, "explain": "FALSE. Only limited companies (private or public) can issue shares. Sole traders and partnerships are unincorporated businesses and cannot raise money in this way."}'::jsonb),
('5-2-sources-of-finance:tf:db6a249d', '5-2-sources-of-finance', '5.2 Sources of Finance', 'tf', 'tf', 1, '{"question": "All businesses will have retained profit available to use."}'::jsonb, '{"answer": false, "explain": "FALSE. Only established businesses that have made a profit and chosen not to distribute all of it to owners will have retained profit. New businesses and loss-making businesses cannot use this source."}'::jsonb),
('5-2-sources-of-finance:tf:fd9b14d1', '5-2-sources-of-finance', '5.2 Sources of Finance', 'tf', 'tf', 1, '{"question": "One disadvantage of taking on a new partner is that the existing owner(s) must share control and future profits."}'::jsonb, '{"answer": true, "explain": "TRUE. A new partner becomes a co-owner of the business. They are entitled to a share of the profits and have the right to participate in decision-making, which reduces the existing owners'' control."}'::jsonb),
('5-2-sources-of-finance:tf:e985b74b', '5-2-sources-of-finance', '5.2 Sources of Finance', 'tf', 'tf', 1, '{"question": "Crowdfunding is only available to established businesses."}'::jsonb, '{"answer": false, "explain": "FALSE. Crowdfunding is available to both new and established businesses. It is often used specifically for start-up and early-stage businesses to raise capital from a large number of online contributors."}'::jsonb),
('5-2-sources-of-finance:tf:dad0eb04', '5-2-sources-of-finance', '5.2 Sources of Finance', 'tf', 'tf', 1, '{"question": "A business that takes out a bank loan may be required to offer security."}'::jsonb, '{"answer": true, "explain": "TRUE. Banks often require security — an asset such as property or equipment — as a guarantee that if the business cannot repay the loan, the bank can sell the asset to recover its money."}'::jsonb),
('5-2-sources-of-finance:tf:aa93364e', '5-2-sources-of-finance', '5.2 Sources of Finance', 'tf', 'tf', 1, '{"question": "Selling assets is always a quick and reliable way to raise finance."}'::jsonb, '{"answer": false, "explain": "FALSE. Selling assets can take time as the business needs to find a willing buyer. There is no guarantee that a buyer can be found, or that the sale price will meet the business''s finance needs."}'::jsonb),
('5-2-sources-of-finance:learn:779f86d8', '5-2-sources-of-finance', '5.2 Sources of Finance', 'learn', 'mcq', 1, '{"readingTitle": "Key Terms & Official Definitions", "reading": "<p>Finance is the money a business uses to fund its activities. Understanding the different sources and uses of finance is essential for any business, whether new or established.</p>\n<ul>\n  <li><strong>Finance:</strong> Money used by a business to fund its operations, start-up costs, expansion or day-to-day expenses.</li>\n  <li><strong>Internal finance:</strong> Money raised from within the business itself, such as retained profit, owner''s capital, or sale of assets.</li>\n  <li><strong>External finance:</strong> Money raised from outside the business, such as loans, share issues, overdrafts, trade credit or crowdfunding.</li>\n  <li><strong>Owner''s capital:</strong> Money from savings put into the business by the owner(s).</li>\n  <li><strong>Retained profit:</strong> Profit that is not distributed to shareholders or owners but is reinvested back into the business.</li>\n  <li><strong>Sale of assets:</strong> Raising finance by selling fixed assets such as machinery or property that the business owns.</li>\n  <li><strong>Overdraft:</strong> An arrangement with a bank that allows a business to spend more money than it has in its account, up to an agreed limit.</li>\n  <li><strong>Trade credit:</strong> An arrangement where a business obtains goods from a supplier without immediate payment — typically 30–90 days interest-free.</li>\n  <li><strong>Loan:</strong> A sum of money borrowed from a bank or lender for a stated purpose and fixed period, repaid with interest.</li>\n  <li><strong>Share issue:</strong> Raising finance by selling new shares in the business; buyers become part-owners (shareholders).</li>\n  <li><strong>Crowdfunding:</strong> Raising money from a large number of contributors — usually via a website such as Kickstarter or Seedrs — through donations, loans or equity.</li>\n  <li><strong>Taking on a new partner:</strong> Inviting someone to join a partnership who contributes capital to the business in exchange for a share of ownership and profits.</li>\n  <li><strong>Interest:</strong> The cost of borrowing money — a percentage charged on the amount owed.</li>\n  <li><strong>Security:</strong> An asset offered to a lender as a guarantee of repayment (e.g. a house or business premises).</li>\n  <li><strong>Dividend:</strong> A share of the company''s profit paid out to shareholders.</li>\n</ul>", "question": "According to the key definitions, what is ''external finance''?", "options": ["Money raised from outside the business, such as loans, share issues or overdrafts", "Money raised from within the business, such as retained profit or owner''s capital", "Money the business receives from selling goods or services to customers", "Money the business pays out to shareholders as a reward for their investment"]}'::jsonb, '{"answer": 0, "explain": "The card defines external finance as money raised from outside the business — such as loans, share issues, overdrafts, trade credit or crowdfunding — unlike internal finance."}'::jsonb),
('5-2-sources-of-finance:learn:78577670', '5-2-sources-of-finance', '5.2 Sources of Finance', 'learn', 'mcq', 1, '{"readingTitle": "Why Businesses Need Finance", "reading": "<p>All businesses will need finance at some stage. The reasons vary depending on whether the business is new or already established, and how much money is needed and for how long.</p>\n<ul>\n  <li><strong>Starting up a new business:</strong> Spending money on capital equipment, recruiting workers, and marketing activities before any revenue is earned.</li>\n  <li><strong>Funding expansion (internal growth):</strong> Buying new machinery, opening new premises, or hiring more staff as the business grows.</li>\n  <li><strong>External growth (takeover/acquisition):</strong> Purchasing another business or merging with a competitor requires a large, often one-off injection of capital.</li>\n  <li><strong>Replacing old machinery, equipment or premises:</strong> Assets wear out or become obsolete and must be updated to maintain productivity.</li>\n  <li><strong>Day-to-day expenses:</strong> Paying wages, buying stock or raw materials, and covering bills — especially when there is a temporary cash-flow problem.</li>\n  <li><strong>Research and development:</strong> Investing in new products or processes to stay competitive.</li>\n  <li><strong>Marketing activities:</strong> Funding campaigns to maintain or increase sales and market share.</li>\n  <li><strong>Recruitment costs:</strong> Advertising, interviewing and training new employees.</li>\n</ul>\n<div class=\"case-study-box\">\n  <h4>Case Study: Makerfield Services Ltd — Short-Term Financing</h4>\n  <p>Makerfield Services Ltd is a small electrical contractor. It needs money day-to-day for wiring, sockets and wages. Cash flow in is not always enough to cover these costs, so it arranges an overdraft facility with its bank — it can overspend by an agreed amount, paying interest only on what it borrows. When revenue arrives, the overdraft is reduced. This illustrates how short-term finance solves a temporary cash-flow problem without committing to a long-term loan.</p>\n</div>", "question": "Which of these is given as a reason a business needs finance in this card?", "options": ["Deciding which television channel to advertise a new product on", "Replacing old machinery, equipment or premises that have become obsolete", "Choosing which supplier offers the best quality raw materials", "Recording customer complaints made about a recent product launch event"]}'::jsonb, '{"answer": 1, "explain": "The card lists replacing worn-out or obsolete assets as a reason a business needs finance; the other options are marketing, procurement and customer service tasks, not reasons for raising finance."}'::jsonb),
('5-2-sources-of-finance:learn:706fc4c7', '5-2-sources-of-finance', '5.2 Sources of Finance', 'learn', 'mcq', 1, '{"readingTitle": "Internal Sources of Finance", "reading": "<p><strong>Internal finance</strong> is raised from within the business. It is generally cheaper because there is no interest to pay, but it is not always available — especially to new businesses.</p>\n<ul>\n  <li><strong>Owner''s capital:</strong> The owner uses their own savings. Available to new and established businesses. No repayment or interest required, but limited by how much the owner has saved.</li>\n  <li><strong>Retained profit:</strong> Profit kept in the business rather than paid out to owners. Only available to established businesses that have already made a profit. No interest or repayment needed.</li>\n  <li><strong>Sale of assets:</strong> Selling machinery, vehicles or property the business no longer needs. Available to established businesses. Generates a one-off lump sum but may take time to find a buyer.</li>\n</ul>\n<div class=\"case-study-box\">\n  <h4>Case Study: Peter Hobson, Gardener — Owner''s Capital</h4>\n  <p>Peter Hobson saved £12,000 from his wages to buy a van and gardening tools to start his own business. He chose to use savings rather than a bank loan because the amount was small and he did not want to risk his family home as security. Later, he used further savings (retained profits) to buy new tools and expand his range of services. This shows how internal finance can fund both start-up and growth without interest costs.</p>\n</div>\n<div class=\"two-col\">\n  <div>\n    <div class=\"col-head\">✓ Advantages of Internal Finance</div>\n    <div class=\"pro-item\"><strong>No interest:</strong> The business does not have to pay a lender, keeping costs lower and protecting profit margins.</div>\n    <div class=\"pro-item\"><strong>No repayment obligation:</strong> Owner''s capital and retained profit do not need to be paid back, reducing financial pressure.</div>\n    <div class=\"pro-item\"><strong>No loss of control:</strong> No outside parties are brought in, so the original owners keep full decision-making power.</div>\n    <div class=\"pro-item\"><strong>No cost to raise:</strong> Unlike a share issue or crowdfunding campaign, internal sources require no fees or promotion.</div>\n  </div>\n  <div>\n    <div class=\"col-head\">✗ Disadvantages of Internal Finance</div>\n    <div class=\"con-item\"><strong>Limited availability:</strong> If the owner has little savings or the business has low profits, internal sources may not raise enough money.</div>\n    <div class=\"con-item\"><strong>Only established businesses have retained profit:</strong> New businesses cannot use this source as they have not yet made any profit.</div>\n    <div class=\"con-item\"><strong>Opportunity cost:</strong> Using savings or retained profit means that money cannot be used elsewhere (e.g. invested in a savings account).</div>\n    <div class=\"con-item\"><strong>Sale of assets takes time:</strong> It may be difficult or slow to find a buyer for machinery or property.</div>\n  </div>\n</div>", "question": "Which of these is correctly identified as an internal source of finance?", "options": ["A bank loan, which is only available to businesses that can offer sufficient security", "Trade credit, which is only available once a supplier agrees the terms", "Retained profit, which is only available to businesses that have already made a profit", "A share issue, which is only available to limited companies"]}'::jsonb, '{"answer": 2, "explain": "The card lists retained profit alongside owner''s capital and sale of assets as internal sources; bank loans, trade credit and share issues are all external sources."}'::jsonb),
('5-2-sources-of-finance:learn:9317b5ae', '5-2-sources-of-finance', '5.2 Sources of Finance', 'learn', 'mcq', 1, '{"readingTitle": "External Sources of Finance", "reading": "<p><strong>External finance</strong> is raised from outside the business. It gives access to larger sums of money but usually involves a cost (interest or loss of ownership).</p>\n<ul>\n  <li><strong>Overdraft:</strong> Short-term arrangement with a bank to spend more than the account balance. Interest is charged on the daily amount overdrawn. Suitable for new and established businesses needing to cover day-to-day cash flow gaps.</li>\n  <li><strong>Trade credit:</strong> The supplier allows the business to pay for goods 30–90 days after receiving them. Typically interest-free within the credit period. Useful for buying stock without immediate cash outlay.</li>\n  <li><strong>Loan:</strong> A fixed sum borrowed from a bank or other lender for a stated period. Repaid in instalments with interest. May require security. Suitable for medium- to long-term investment such as machinery or premises.</li>\n  <li><strong>Share issue:</strong> Selling new shares to investors who become part-owners. Available to limited companies only. Raises large sums without repayment or interest, but shareholders gain a say in the business.</li>\n  <li><strong>Crowdfunding:</strong> Raising money from many contributors via a website (e.g. Kickstarter). Contributors may donate, lend, or buy equity. Suitable for start-ups and expansion. No security needed for loans, but success is not guaranteed.</li>\n  <li><strong>Taking on a new partner:</strong> A new partner contributes capital and joins the partnership. Long-term source available to partnerships only. May bring new skills but reduces control for existing partners.</li>\n</ul>\n<div class=\"case-study-box\">\n  <h4>Case Study: Chineasy — Crowdfunding a Start-Up</h4>\n  <p>ShaoLan Hsueh needed finance to develop a course to help Western people learn Chinese characters, including books, flash cards and a website. She used Kickstarter to raise nearly £200,000 within a month — well above her £75,000 target — by promoting her idea on social media. Contributors became shareholders in Chineasy Limited. This case shows how crowdfunding can reach a large number of investors quickly, removing the need for a bank loan or traditional investor.</p>\n</div>", "question": "Which of these external sources is limited-company-only, according to this card?", "options": ["Overdraft, which allows the business to spend more than its account balance", "Trade credit, which allows the business to delay paying its suppliers", "Crowdfunding, which allows the business to raise money from a website", "Share issue, which allows the business to sell new shares to investors"]}'::jsonb, '{"answer": 3, "explain": "The card states a share issue is available to limited companies only, since it involves selling shares — overdrafts, trade credit and crowdfunding are open to a wider range of business types."}'::jsonb),
('5-2-sources-of-finance:learn:71f3bc6c', '5-2-sources-of-finance', '5.2 Sources of Finance', 'learn', 'mcq', 1, '{"readingTitle": "Advantages & Disadvantages of Each External Source", "reading": "<p>The table below summarises the pros and cons of each external source of finance. This is the most commonly tested area in the exam — you must be able to apply these to a specific business context.</p>\n\n<p><strong>Overdraft</strong></p>\n<div class=\"two-col\">\n  <div>\n    <div class=\"col-head\">✓ Advantages</div>\n    <div class=\"pro-item\">Flexible — interest is only charged on the amount overdrawn each day.</div>\n    <div class=\"pro-item\">Quick to arrange if the business already has a bank account.</div>\n    <div class=\"pro-item\">Helps the business continue trading through short-term cash shortages.</div>\n  </div>\n  <div>\n    <div class=\"col-head\">✗ Disadvantages</div>\n    <div class=\"con-item\">Interest rates on overdrafts are high — can be expensive if used for a long time.</div>\n    <div class=\"con-item\">The bank can demand repayment at short notice.</div>\n    <div class=\"con-item\">Not suitable for long-term investment needs.</div>\n  </div>\n</div>\n\n<p><strong>Trade Credit</strong></p>\n<div class=\"two-col\">\n  <div>\n    <div class=\"col-head\">✓ Advantages</div>\n    <div class=\"pro-item\">Typically interest-free within the agreed credit period.</div>\n    <div class=\"pro-item\">Allows the business to sell goods before paying the supplier, improving cash flow.</div>\n  </div>\n  <div>\n    <div class=\"col-head\">✗ Disadvantages</div>\n    <div class=\"con-item\">Goods must be paid for even if they do not sell.</div>\n    <div class=\"con-item\">Interest is charged if payment is not made within the time limit.</div>\n  </div>\n</div>\n\n<p><strong>Bank Loan</strong></p>\n<div class=\"two-col\">\n  <div>\n    <div class=\"col-head\">✓ Advantages</div>\n    <div class=\"pro-item\">Repayment is spread over time in fixed instalments, aiding budgeting.</div>\n    <div class=\"pro-item\">Can be arranged for a specific amount and purpose.</div>\n  </div>\n  <div>\n    <div class=\"col-head\">✗ Disadvantages</div>\n    <div class=\"con-item\">Interest must be paid throughout the term, increasing the total cost.</div>\n    <div class=\"con-item\">The bank may require security — the business risks losing an asset if it defaults.</div>\n  </div>\n</div>\n\n<p><strong>Share Issue</strong></p>\n<div class=\"two-col\">\n  <div>\n    <div class=\"col-head\">✓ Advantages</div>\n    <div class=\"pro-item\">Large sums can be raised from many investors.</div>\n    <div class=\"pro-item\">No interest and no repayment required.</div>\n    <div class=\"pro-item\">Shareholders may bring expertise and contacts to the business.</div>\n  </div>\n  <div>\n    <div class=\"col-head\">✗ Disadvantages</div>\n    <div class=\"con-item\">Shareholders gain a say in how the business is run, reducing owners'' control.</div>\n    <div class=\"con-item\">Dividends may need to be paid to shareholders from profits.</div>\n    <div class=\"con-item\">Risk of takeover if too many shares are sold (more of a risk for public limited companies).</div>\n  </div>\n</div>\n\n<p><strong>Crowdfunding</strong></p>\n<div class=\"two-col\">\n  <div>\n    <div class=\"col-head\">✓ Advantages</div>\n    <div class=\"pro-item\">Can raise large amounts from many contributors with no security needed.</div>\n    <div class=\"pro-item\">Generates publicity and a community of supporters around the business.</div>\n  </div>\n  <div>\n    <div class=\"col-head\">✗ Disadvantages</div>\n    <div class=\"con-item\">Not guaranteed — the business may not reach its funding target.</div>\n    <div class=\"con-item\">Requires time and effort to promote the campaign; publicity stunts can be costly.</div>\n    <div class=\"con-item\">If equity is sold, profits must be shared with contributors.</div>\n  </div>\n</div>\n\n<p><strong>Taking on a New Partner</strong></p>\n<div class=\"two-col\">\n  <div>\n    <div class=\"col-head\">✓ Advantages</div>\n    <div class=\"pro-item\">Provides a long-term injection of capital at no direct financial cost (no interest).</div>\n    <div class=\"pro-item\">The new partner may bring valuable skills and experience to the business.</div>\n  </div>\n  <div>\n    <div class=\"col-head\">✗ Disadvantages</div>\n    <div class=\"con-item\">The new partner shares ownership, profits and decision-making power.</div>\n    <div class=\"con-item\">The partner may not have the required skills or enough capital to meet the business''s needs.</div>\n    <div class=\"con-item\">Decision-making can become slower and lead to disagreements.</div>\n  </div>\n</div>", "question": "According to this card, what is a key disadvantage of using a share issue?", "options": ["Shareholders gain a say in how the business is run, reducing owners'' control", "Interest rates on a share issue are extremely high compared with a bank loan", "The bank can demand repayment of a share issue at very short notice", "Goods bought through a share issue must be paid for even if unsold"]}'::jsonb, '{"answer": 0, "explain": "The card lists reduced owner control as a disadvantage of a share issue, since shareholders gain a say in the business — share issues do not carry interest or bank repayment demands."}'::jsonb),
('5-2-sources-of-finance:learn:b556f84d', '5-2-sources-of-finance', '5.2 Sources of Finance', 'learn', 'mcq', 1, '{"readingTitle": "Short-, Medium- and Long-Term Finance", "reading": "<p>Businesses need finance for different lengths of time. Matching the time period of the finance to the purpose is important — using a short-term source for a long-term investment would be costly and risky.</p>\n<ul>\n  <li><strong>Short-term finance (up to 12 months):</strong> Used for day-to-day running costs such as wages, stock and bills. Examples: overdraft, trade credit.</li>\n  <li><strong>Medium-term finance (1–5 years):</strong> Used for machinery, vehicles, or extending premises. Examples: bank loan, owners'' capital, retained profit, sale of assets.</li>\n  <li><strong>Long-term finance (5 years or more):</strong> Used for major investments such as new buildings, takeovers, or large-scale expansion. Examples: share issue, crowdfunding, taking on a new partner, bank loan.</li>\n</ul>\n<p>Some sources of finance span more than one time period — for example, a bank loan can be medium or long term depending on the repayment schedule.</p>\n<p>Not all sources of finance are available to every business. Key constraints include:</p>\n<ul>\n  <li>Sole traders and partnerships <strong>cannot issue shares</strong> — this is only available to limited companies.</li>\n  <li>Limited companies <strong>cannot take on extra partners</strong>.</li>\n  <li>Businesses with a poor financial record may struggle to get a bank loan.</li>\n  <li>Retained profit is <strong>only available to established businesses</strong> that have already generated profit.</li>\n</ul>", "question": "Which of these is classed as a short-term source of finance in this card?", "options": ["Share issue, used to fund major long-term expansion projects", "Overdraft, used to cover day-to-day running costs such as wages and stock", "Bank loan, used to purchase machinery over several years", "Taking on a new partner, used for a long-term injection of capital funds"]}'::jsonb, '{"answer": 1, "explain": "The card classifies overdraft (alongside trade credit) as short-term finance, used for day-to-day costs — share issues, most bank loans and new partners are medium- or long-term."}'::jsonb),
('5-2-sources-of-finance:learn:1c6141b0', '5-2-sources-of-finance', '5.2 Sources of Finance', 'learn', 'mcq', 1, '{"readingTitle": "Choosing the Right Source of Finance", "reading": "<p>When choosing a source of finance, a business must consider several key factors:</p>\n<ul>\n  <li><strong>The purpose:</strong> What is the money for? Day-to-day costs need short-term finance; a new building needs long-term finance.</li>\n  <li><strong>The amount needed:</strong> Small amounts can come from an overdraft or owner''s savings; large sums may require a share issue or crowdfunding.</li>\n  <li><strong>The cost:</strong> Interest on loans and overdrafts increases the total cost. Internal finance (retained profit, owner''s capital) has no interest but has an opportunity cost.</li>\n  <li><strong>The type of business:</strong> A sole trader cannot issue shares. A new business has no retained profit. A partnership cannot issue shares but can take on a new partner.</li>\n  <li><strong>Control:</strong> Share issues and new partners reduce the owner''s control. Loans and overdrafts do not affect ownership.</li>\n  <li><strong>Risk:</strong> Loans require security; if the business fails, the lender may repossess assets. Internal finance carries no such risk.</li>\n</ul>\n<div class=\"case-study-box\">\n  <h4>Case Study: Brew Dog — Crowdfunding for Expansion</h4>\n  <p>Brew Dog, the Scottish craft beer company, raised over £100 million through crowdfunding between 2011 and 2021 by selling shares via social media campaigns. In 2020 it launched a new crowdfund targeting £50 million to open new bars worldwide, build breweries and buy farmland. Beer enthusiasts who invested received discounts and free birthday beers. Brew Dog deliberately avoided bank loans because it feared lenders would gain too much influence over business decisions. This shows how a business''s values and desire for independence can shape its choice of finance, not just the cost.</p>\n</div>\n<div class=\"case-study-box\">\n  <h4>Case Study: Everton FC — Share Issue and Loans</h4>\n  <p>In 2020–21, Everton Football Club needed finance for three reasons: lost matchday revenue due to COVID-19, new player signings costing over £180 million, and a new £500 million stadium project. The club issued £250 million of new shares to its existing owner Farhad Moshiri and planned to borrow the rest from private lenders. This illustrates how large, established organisations may use a combination of share issues and loans to fund major long-term investments.</p>\n</div>", "question": "Which factor does this card identify as affecting the choice of finance source?", "options": ["Colour, since some sources are only available to businesses with a certain brand image", "Location, since some sources are only available in certain towns or cities", "Control, since share issues and new partners reduce the owner''s decision-making power", "Weather, since seasonal businesses cannot use any external sources at all"]}'::jsonb, '{"answer": 2, "explain": "The card lists control as a factor in choosing finance, since share issues and new partners reduce the owner''s control, unlike loans or overdrafts which do not affect ownership."}'::jsonb),
('5-2-sources-of-finance:learn:c05c51a9', '5-2-sources-of-finance', '5.2 Sources of Finance', 'learn', 'mcq', 1, '{"readingTitle": "Share Issue Calculations", "reading": "<p>In the exam you may be asked to calculate the total amount of money raised by a share issue. The formula is simple:</p>\n<div class=\"formula-box\">\n  <strong>Total Finance Raised = </strong> Number of shares sold &times; Price per share\n</div>\n<p>For example, if a company sells 10,000 shares at £1.50 each:</p>\n<div class=\"formula-box\">\n  10,000 &times; £1.50 = <strong>£15,000 raised</strong>\n</div>\n<p>If it sold all 50,000 available shares at £1.50:</p>\n<div class=\"formula-box\">\n  50,000 &times; £1.50 = <strong>£75,000 raised</strong>\n</div>\n<p>If it sold 50% of 50,000 shares (= 25,000) at £1.50:</p>\n<div class=\"formula-box\">\n  25,000 &times; £1.50 = <strong>£37,500 raised</strong>\n</div>\n<p>Also note: interest on a bank loan is calculated as:</p>\n<div class=\"formula-box\">\n  <strong>Annual Interest = </strong> Loan Amount &times; Interest Rate (%)\n</div>\n<p>Example: A £12,000 loan at 8% interest per year = £12,000 &times; 0.08 = <strong>£960 interest in year 1</strong></p>", "question": "How is the total finance raised by a share issue calculated?", "options": ["Number of shares sold divided by the price per share", "Total profit of the business divided by the number of shareholders", "Loan amount multiplied by the annual interest rate percentage", "Number of shares sold multiplied by the price per share"]}'::jsonb, '{"answer": 3, "explain": "The card gives the formula Total Finance Raised = Number of shares sold x Price per share — the interest formula (loan x rate) is a different calculation used for bank loans."}'::jsonb),
('5-2-sources-of-finance:misc:020a7044', '5-2-sources-of-finance', '5.2 Sources of Finance', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Retained profit is a pot of cash sitting in the business that can be spent at any time.</p><p><strong>✅ The correct idea:</strong> Retained profit is an accounting figure showing profits not paid out to owners. The cash from those profits has likely already been used in day-to-day operations. Only if cash has been physically set aside will the business have a lump sum to invest.</p>", "question": "What is the correct view of what ''retained profit'' represents?", "options": ["An accounting figure for profit not paid out, which may already be spent on operations", "A pot of cash sitting untouched in the business that can be spent at any time at all", "A loan from the bank that must be repaid together with interest charges", "A fee charged to shareholders for holding shares in the business"]}'::jsonb, '{"answer": 0, "explain": "The card explains retained profit is an accounting figure, not necessarily a cash pile — the cash from those profits may already have been used in day-to-day operations."}'::jsonb),
('5-2-sources-of-finance:misc:25d95820', '5-2-sources-of-finance', '5.2 Sources of Finance', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> All sources of finance are available to every type of business.</p><p><strong>✅ The correct idea:</strong> Different sources are available to different types of businesses. For example, share issues are only for limited companies; taking on a partner is only for sole traders/partnerships; retained profit is only for established businesses.</p>", "question": "Which statement correctly describes the availability of finance sources?", "options": ["Every single source of finance is available equally to any type of business at all", "Different sources are available to different types of business, such as share issues", "Only limited companies are able to raise any finance at all", "Only sole traders are restricted from using any external finance sources"]}'::jsonb, '{"answer": 1, "explain": "The card corrects the misconception that all sources are available to everyone — share issues suit limited companies, taking a partner suits sole traders/partnerships, and retained profit needs an established business."}'::jsonb),
('5-2-sources-of-finance:misc:0f32266c', '5-2-sources-of-finance', '5.2 Sources of Finance', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> An overdraft is a good way to fund a major long-term investment like buying a building.</p><p><strong>✅ The correct idea:</strong> An overdraft is a short-term source designed for day-to-day cash flow problems. It is expensive (high daily interest) and not suitable for long-term investments. A bank loan or share issue would be more appropriate.</p>", "question": "Why is an overdraft not suitable for funding a major long-term investment?", "options": ["It is only available to businesses that have already made a large profit", "It requires the business to sell part of its ownership to a bank", "It is a short-term, expensive source designed for day-to-day cash flow gaps", "It cannot legally be arranged unless the business has zero debt"]}'::jsonb, '{"answer": 2, "explain": "The card explains an overdraft is short-term and expensive (high daily interest), designed for day-to-day cash flow problems rather than major long-term investments like buying a building."}'::jsonb),
('5-2-sources-of-finance:misc:06fee2a2', '5-2-sources-of-finance', '5.2 Sources of Finance', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Interest is only a disadvantage of bank loans.</p><p><strong>✅ The correct idea:</strong> Interest applies to overdrafts and trade credit (if not paid on time) as well as loans. Crowdfunding loans also carry interest. The only sources with no interest are internal sources (owner''s capital, retained profit) and share issues.</p>", "question": "Which sources of finance can also involve paying interest, besides bank loans?", "options": ["Owner''s capital and retained profit are the only other examples", "Share issues and taking on a new partner are the only other examples", "Sale of assets and retained profit are the only other examples", "Overdrafts and late trade credit, as well as crowdfunding loans"]}'::jsonb, '{"answer": 3, "explain": "The card corrects the idea that interest only applies to bank loans — overdrafts, late trade credit payments, and crowdfunding loans can all involve interest too."}'::jsonb),
('5-2-sources-of-finance:misc:7774e662', '5-2-sources-of-finance', '5.2 Sources of Finance', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Taking on a new partner means hiring a new employee who earns a salary.</p><p><strong>✅ The correct idea:</strong> A new partner is a co-owner of the business, not an employee. They contribute capital, share in the profits AND losses, and have the right to take part in decision-making. They do not earn a fixed salary.</p>", "question": "What is the correct status of a new partner joining a business?", "options": ["A co-owner who contributes capital and shares in profits and losses", "An employee who is paid a fixed salary for the work they do", "A lender who is repaid with interest over a fixed period of time", "A shareholder who receives a dividend but has no voting rights"]}'::jsonb, '{"answer": 0, "explain": "The card explains a new partner is a co-owner, not an employee — they contribute capital, share in profits AND losses, and take part in decision-making rather than earning a salary."}'::jsonb),
('5-2-sources-of-finance:misc:663fc108', '5-2-sources-of-finance', '5.2 Sources of Finance', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Using your own savings to finance a business is completely free with no cost at all.</p><p><strong>✅ The correct idea:</strong> Owner''s capital has no interest cost, but it does have an opportunity cost — the money could have been earning interest in a bank account or invested elsewhere. There is also the risk of losing personal savings if the business fails.</p>", "question": "What cost does using owner''s savings to finance a business actually involve?", "options": ["No cost of any kind at all, since savings are always entirely free to use", "An opportunity cost, since the money could have earned interest elsewhere", "Interest charged by the bank on the amount of savings used", "A fee paid to shareholders for the use of their personal savings"]}'::jsonb, '{"answer": 1, "explain": "The card explains owner''s capital has no interest cost but does have an opportunity cost, since the money could have earned interest elsewhere or been invested another way."}'::jsonb),
('5-2-sources-of-finance:misc:682a7325', '5-2-sources-of-finance', '5.2 Sources of Finance', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> For a ''recommend'' question, you only need to give reasons FOR your chosen option to get full marks.</p><p><strong>✅ The correct idea:</strong> OCR examiners require a comparative answer — you must explain why your chosen option is BETTER THAN the alternative. Answers that only discuss the chosen option without referencing the rejected option cannot score more than 1 mark for justification.</p>", "question": "What must a full-mark answer to a ''recommend'' question include?", "options": ["Only reasons for the chosen option, without ever mentioning the alternative", "A complete list of every possible source of finance available", "A comparison explaining why the chosen option is better than the alternative", "A general definition of finance with no reference to either option"]}'::jsonb, '{"answer": 2, "explain": "The card explains OCR requires a comparative answer justifying why the chosen option is better than the rejected one — answers covering only the chosen option score at most 1 mark."}'::jsonb),
('5-2-sources-of-finance:misc:43174c78', '5-2-sources-of-finance', '5.2 Sources of Finance', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> A share issue means the business has to repay shareholders like a loan.</p><p><strong>✅ The correct idea:</strong> Money raised through a share issue does not need to be repaid. Shareholders own part of the business and may receive dividends if profits are made and distributed, but the original sum invested is not returned to them.</p>", "question": "Does money raised through a share issue need to be repaid like a loan?", "options": ["Yes — shareholders must be repaid the full amount plus additional interest", "Yes — but only if the business fails to make a profit that year", "No — but only if the shareholders agree in writing to waive repayment", "No — shareholders own part of the business and are not repaid the original sum"]}'::jsonb, '{"answer": 3, "explain": "The card corrects the misconception that a share issue must be repaid — shareholders own part of the business and may receive dividends, but the original investment is not repaid to them."}'::jsonb),
('5-2-sources-of-finance:misc:6f6832f3', '5-2-sources-of-finance', '5.2 Sources of Finance', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Crowdfunding always means people are donating money with nothing in return.</p><p><strong>✅ The correct idea:</strong> Crowdfunding can work in three ways: donors give money (common for community projects), lenders provide a loan (repaid with interest), or investors buy equity (a share of the business). Most business crowdfunding involves equity or lending.</p>", "question": "What does the card say about how crowdfunding contributions actually work?", "options": ["Contributors may donate, lend, or buy equity — not just donate with nothing back", "Contributors always donate money with absolutely nothing given back in return", "Contributors always receive a fixed rate of interest on their money", "Contributors always become full legal business partners as a result"]}'::jsonb, '{"answer": 0, "explain": "The card explains crowdfunding can work three ways — donation, loan, or equity — correcting the idea that it always means donations with nothing given in return."}'::jsonb),
('5-2-sources-of-finance:misc:733842c9', '5-2-sources-of-finance', '5.2 Sources of Finance', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> A bank loan and an overdraft are essentially the same thing.</p><p><strong>✅ The correct idea:</strong> They are very different. A bank loan is a fixed sum borrowed for a fixed period with set instalments. An overdraft is a flexible, daily arrangement where interest is charged only on the amount overdrawn — it varies day by day and is meant for short-term needs.</p>", "question": "What is the key difference between a bank loan and an overdraft?", "options": ["A loan and an overdraft are essentially identical arrangements with a bank", "A loan is a fixed sum for a fixed period, while an overdraft is a flexible daily arrangement", "A loan is repaid daily, while an overdraft is repaid in one single lump sum", "A loan requires no interest to be paid at all, while an overdraft always charges some interest"]}'::jsonb, '{"answer": 1, "explain": "The card explains a bank loan is a fixed sum for a fixed period with set instalments, while an overdraft is a flexible daily arrangement charged only on the amount overdrawn."}'::jsonb),
('5-2-sources-of-finance:tips:4182efcb', '5-2-sources-of-finance', '5.2 Sources of Finance', 'tips', 'mcq', 1, '{"readingTitle": "Identify / State — 1 mark — One Point. Full Stop. Move On.", "reading": "\n      <p>A 1-mark <strong>''Identify'' or ''State''</strong> question needs exactly one correct, specific point. No explanation. No examples. No paragraphs.</p>\n      <p><strong>Common question types:</strong></p>\n      <ul>\n        <li>\"Identify one reason, other than expansion, why a business needs finance.\" [1 mark]</li>\n        <li>\"State one disadvantage of using an overdraft.\" [1 mark]</li>\n      </ul>\n      <p><strong>❌ Bad Answer (0 marks):</strong><br/>\n      <em>\"Finance.\"</em><br/>\n      Too vague — this doesn''t state anything about the business.</p>\n      <p><strong>✅ Good Answer (1 mark):</strong><br/>\n      <em>\"To pay for day-to-day expenses such as wages and stock.\"</em><br/>\n      Specific and directly answers the question.</p>\n      <p><strong>⚠️ Examiner Warning:</strong> If the question says \"other than expansion\", any answer linked to growth or opening new premises scores zero — even if it''s perfectly correct business knowledge. Always re-read the exact wording.</p>\n    ", "question": "What must you avoid when answering a question that says ''other than expansion''?", "options": ["Giving an answer that mentions day-to-day running costs like wages", "Giving an answer that mentions research and development costs", "Giving any answer linked to growth or opening new premises", "Giving an answer that mentions replacing old machinery or equipment"]}'::jsonb, '{"answer": 2, "explain": "The card warns that when a question excludes expansion, any growth-related answer scores zero — even if it is otherwise correct business knowledge — so re-read the exact wording."}'::jsonb),
('5-2-sources-of-finance:tips:0db32b21', '5-2-sources-of-finance', '5.2 Sources of Finance', 'tips', 'mcq', 1, '{"readingTitle": "State One Disadvantage — 2 marks (1+1) — Two Disadvantages, One Each — Don''t Confuse Them", "reading": "\n      <p>Some questions ask you to state one disadvantage of <strong>two different sources of finance</strong> — one mark each. These are knowledge-only questions, so no application or analysis is needed.</p>\n      <p><strong>Example question:</strong> \"State one disadvantage to a business owner of using: (a) their own capital, (b) a bank loan.\" [2 marks]</p>\n      <p><strong>Formula:</strong> State the disadvantage clearly for each source. Keep it simple.</p>\n      <p><strong>✅ Owner''s capital (1 mark):</strong><br/>\n      <em>\"Using savings will leave the owner with less money for personal use / emergencies.\"</em></p>\n      <p><strong>✅ Bank loan (1 mark):</strong><br/>\n      <em>\"Interest must be paid on the loan, increasing the total cost for the business.\"</em></p>\n      <p><strong>⚠️ Examiner Warning:</strong> Students often write a disadvantage of the wrong source — e.g. writing about interest for owner''s capital. Always make sure your disadvantage logically matches the source it''s asking about.</p>\n    ", "question": "What is the most common mistake in a ''state one disadvantage of each'' question?", "options": ["Writing far more disadvantages than the actual number the question really asks for", "Failing to mention any specific source of finance at all in the answer", "Writing the disadvantage using bullet points instead of full sentences", "Writing a disadvantage that doesn''t logically match the source being asked about"]}'::jsonb, '{"answer": 3, "explain": "The card warns students often write a disadvantage of the wrong source — e.g. mentioning interest for owner''s capital — so the disadvantage must logically match the source asked about."}'::jsonb),
('5-2-sources-of-finance:tips:7a5f032e', '5-2-sources-of-finance', '5.2 Sources of Finance', 'tips', 'mcq', 1, '{"readingTitle": "Analyse — 3 marks — The U → APP → AN Chain: Three Steps, Zero Shortcuts", "reading": "\n      <p>For a 3-mark analyse question, you need to follow the <strong>Understanding → Application → Analysis</strong> chain. You will score ZERO for the analysis mark if you do not apply to the specific business in the case study.</p>\n      <p><strong>The 3-step formula:</strong></p>\n      <ul>\n        <li><strong>Step 1 — Understanding (U):</strong> State the benefit or drawback of this source of finance. What is it?</li>\n        <li><strong>Step 2 — Application (APP):</strong> Link it to the specific business in the case study. Use their name, figures, or context.</li>\n        <li><strong>Step 3 — Analysis (AN):</strong> Explain the financial or operational impact on the business. What does this mean for their costs, cash flow, profit, or growth?</li>\n      </ul>\n      <p><strong>Sentence starters:</strong><br/>\n      U: \"A share issue means the business can raise money without paying interest...\"<br/>\n      APP: \"For CFM, which has a negative closing balance of -£5,500...\"<br/>\n      AN: \"...this will reduce their financial costs, helping them improve their net profit margin.\"</p>\n      <p><strong>❌ Bad Answer (1 mark max):</strong><br/>\n      <em>\"A share issue is good because it raises money. This is good for the business.\"</em><br/>\n      No application to the case study, no real analysis.</p>\n      <p><strong>✅ Full-Mark Answer (3 marks):</strong><br/>\n      <em>\"A share issue raises finance without requiring repayment (U). This is useful for CFM as they are considering becoming a private limited company and need to fund a new café costing several thousand pounds (APP). By avoiding a bank loan, Martin and Anne will not have to pay interest, keeping their costs low and protecting their 25% net profit margin (AN).\"</em></p>\n      <p><strong>🚫 Examiner Warning — \"Knowledge Dumping\":</strong> Writing everything you know about share issues without referring to the specific business scores very few marks. The examiner is testing whether you can apply theory to context, not just recall theory.</p>\n    ", "question": "What score do you get for the analysis mark if you don''t apply to the case study business?", "options": ["Zero — the analysis mark requires application to the specific business", "Full marks, since analysis can always be entirely theoretical", "Half marks, since basic understanding alone still counts for quite a lot", "One mark, regardless of whether or not you apply the answer"]}'::jsonb, '{"answer": 0, "explain": "The card states you score zero for the analysis mark without applying to the case study business — the U to APP to AN chain requires application before analysis can be credited."}'::jsonb),
('5-2-sources-of-finance:tips:8f829016', '5-2-sources-of-finance', '5.2 Sources of Finance', 'tips', 'mcq', 1, '{"readingTitle": "Recommend — 3 marks — You MUST Compare Both Options to Get Full Marks", "reading": "\n      <p>A 3-mark ''Recommend'' question asks you to choose between <strong>two specific sources of finance</strong> and justify your choice. This is the most commonly failed question type on this topic.</p>\n      <p><strong>The 3-mark formula:</strong></p>\n      <ul>\n        <li><strong>Mark 1 — Judgement:</strong> State your clear recommendation. \"CFM should use retained profit / a share issue.\"</li>\n        <li><strong>Mark 2 — Justification:</strong> Explain why your chosen option is BETTER THAN the other. You must cover BOTH methods.</li>\n        <li><strong>Mark 3 — Context:</strong> Embed a specific detail from the case study to support your comparison.</li>\n      </ul>\n      <p><strong>Sentence starter:</strong><br/>\n      \"I recommend [Option A] because... Unlike [Option B], this will... Given that the case study states [specific detail], this means...\"</p>\n      <p><strong>❌ Bad Answer (1 mark only):</strong><br/>\n      <em>\"CFM should use retained profit. It is free and they won''t have to pay it back.\"</em><br/>\n      This only discusses the chosen option — no comparison with a share issue, no context.</p>\n      <p><strong>✅ Full-Mark Answer:</strong><br/>\n      <em>\"CFM should use retained profit (JUDGEMENT). Unlike a share issue, retained profit does not require Martin and Anne to sell part of their business, so they keep full control (JUSTIFICATION). Since CFM has only been trading for two years and has a negative cash flow forecast (-£5,500 closing balance), bringing in outside shareholders could lead to pressure to prioritise profit over the partners'' goals (CONTEXT).\"</em></p>\n      <p><strong>⚠️ Examiner Warning:</strong> Over 50% of students fail to score more than 1 mark on this type of question. The most common mistake is repeating points from the previous two questions without making a clear comparison. The examiner wants new reasoning — not a summary of what you already said.</p>\n    ", "question": "According to this card, why do most students fail to score well on ''recommend'' questions?", "options": ["They recommend an option that isn''t actually mentioned anywhere in the case study", "They repeat earlier points without making a clear comparison between the two options", "They write far more detail than the three available marks actually require", "They forget to state any final judgement anywhere in their answer"]}'::jsonb, '{"answer": 1, "explain": "The card explains over 50% of students fail to score more than 1 mark by repeating earlier points instead of making a genuine new comparison between the two options."}'::jsonb),
('5-2-sources-of-finance:tips:7bf67d17', '5-2-sources-of-finance', '5.2 Sources of Finance', 'tips', 'mcq', 1, '{"readingTitle": "Evaluate — 7 marks — Argue Both Sides, Then Make a Justified Conclusion", "reading": "\n      <p>A 7-mark evaluate question uses Levels of Response marking. You need to demonstrate application, analysis AND evaluation — in that order.</p>\n      <p><strong>Structure your answer in 4 paragraphs:</strong></p>\n      <p><strong>Paragraph 1 — Understanding & Option A (K + U):</strong><br/>\n      Explain what source of finance A is and one reason it could be appropriate.<br/>\n      <em>\"Owner''s capital is money the owner uses from their own savings. For Martina, who has just over £5,000 in savings, this would mean no interest payments...\"</em></p>\n      <p><strong>Paragraph 2 — Analysis & Application of Option A (AN + APP):</strong><br/>\n      Develop the impact on the business using case study details.<br/>\n      <em>\"However, as the equipment costs £5,000 and Martina has just over £5,000 saved, using all her savings would leave her with almost nothing to fall back on in the first months of trading, when the clinic is unlikely to be fully booked...\"</em></p>\n      <p><strong>Paragraph 3 — Analysis & Application of Option B (AN + APP):</strong><br/>\n      Now consider the second option (e.g. bank loan) with its impact.<br/>\n      <em>\"A bank loan would allow Martina to keep her savings as a financial safety net. However, interest charges would increase her monthly fixed costs, putting pressure on MD Sports Clinic''s cash flow, especially in its early months...\"</em></p>\n      <p><strong>Paragraph 4 — Evaluation (3 points: Decision + Context + Impact/Reasoning):</strong><br/>\n      Make a justified conclusion that goes beyond simply repeating your analysis.<br/>\n      <em>\"Overall, I recommend the bank loan. This is because Martina''s savings are barely enough to cover the equipment cost — leaving her with no contingency fund is very risky for a new business. The interest cost is manageable if she secures a low rate, and her stable cash flow forecast suggests she can afford the repayments. Ultimately, it depends on the interest rate offered — if it is high, using savings becomes more attractive.\"</em></p>\n      <p><strong>\"It Depends On...\" Rule:</strong> A conclusion that simply says \"Option A is best\" without nuance scores few evaluation marks. Examiners reward answers that identify the key condition or factor the decision hinges on.</p>\n    ", "question": "What do examiners reward in the final evaluation paragraph, according to this card?", "options": ["Simply stating that one option is the best one without giving any further reasoning", "Repeating the two earlier analysis paragraphs in a slightly shorter form", "Identifying the key condition or factor that the final decision actually depends on", "Avoiding a final decision so that both options remain equally valid"]}'::jsonb, '{"answer": 2, "explain": "The card''s ''It Depends On...'' rule explains examiners reward identifying the key factor the decision hinges on, rather than a bare judgement or a repeat of earlier analysis."}'::jsonb),
('5-2-sources-of-finance:fib:87f5f327', '5-2-sources-of-finance', '5.2 Sources of Finance', 'fib', 'fib', 2, '{"question": "An overdraft is a _____ source of finance that allows a business to spend more than it has in its _____.", "blankOptions": {"B1": ["10,500", "capital", "short-term", "interest-free"], "B2": ["long-term", "running", "assets", "bank account"]}}'::jsonb, '{"blanks": {"B1": "short-term", "B2": "bank account"}}'::jsonb),
