('5-2-sources-of-finance:match:b34558f7', '5-2-sources-of-finance', '5.2 Sources of Finance', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Retained profit”?", "options": ["An arrangement with a bank that allows a business to spend more money than it has in its current account, up to an agreed limit.", "Profit that is not distributed to shareholders as a dividend but is reinvested back into the business.", "An arrangement where a business obtains goods from a supplier without making immediate payment, typically repaying within 30–90 days.", "Raising finance by selling new shares in the business; buyers become part-owners (shareholders) and may receive dividends."]}'::jsonb, '{"answer": 1, "explain": "“Retained profit” means: Profit that is not distributed to shareholders as a dividend but is reinvested back into the business."}'::jsonb),
('5-2-sources-of-finance:match:05fc497d', '5-2-sources-of-finance', '5.2 Sources of Finance', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Overdraft”?", "options": ["An arrangement where a business obtains goods from a supplier without making immediate payment, typically repaying within 30–90 days.", "Raising finance by selling new shares in the business; buyers become part-owners (shareholders) and may receive dividends.", "An arrangement with a bank that allows a business to spend more money than it has in its current account, up to an agreed limit.", "Raising money from a large number of contributors — usually via a website — through donations, loans or equity investment."]}'::jsonb, '{"answer": 2, "explain": "“Overdraft” means: An arrangement with a bank that allows a business to spend more money than it has in its current account, up to an agreed limit."}'::jsonb),
('5-2-sources-of-finance:match:01184653', '5-2-sources-of-finance', '5.2 Sources of Finance', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Trade credit”?", "options": ["An arrangement where a business obtains goods from a supplier without making immediate payment, typically repaying within 30–90 days.", "Raising finance by selling new shares in the business; buyers become part-owners (shareholders) and may receive dividends.", "Raising money from a large number of contributors — usually via a website — through donations, loans or equity investment.", "Money from the owner''s own savings invested into the business to provide start-up or development finance."]}'::jsonb, '{"answer": 0, "explain": "“Trade credit” means: An arrangement where a business obtains goods from a supplier without making immediate payment, typically repaying within 30–90 days."}'::jsonb),
('5-2-sources-of-finance:match:c0e3ca0f', '5-2-sources-of-finance', '5.2 Sources of Finance', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Share issue”?", "options": ["Raising money from a large number of contributors — usually via a website — through donations, loans or equity investment.", "Raising finance by selling new shares in the business; buyers become part-owners (shareholders) and may receive dividends.", "Money from the owner''s own savings invested into the business to provide start-up or development finance.", "A fixed sum of money borrowed from a bank for a stated purpose and period, repaid with interest in instalments."]}'::jsonb, '{"answer": 1, "explain": "“Share issue” means: Raising finance by selling new shares in the business; buyers become part-owners (shareholders) and may receive dividends."}'::jsonb),
('5-2-sources-of-finance:match:012a6445', '5-2-sources-of-finance', '5.2 Sources of Finance', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Crowdfunding”?", "options": ["Money from the owner''s own savings invested into the business to provide start-up or development finance.", "A fixed sum of money borrowed from a bank for a stated purpose and period, repaid with interest in instalments.", "A new partner contributes capital to a partnership in exchange for a share of ownership and future profits.", "Raising money from a large number of contributors — usually via a website — through donations, loans or equity investment."]}'::jsonb, '{"answer": 3, "explain": "“Crowdfunding” means: Raising money from a large number of contributors — usually via a website — through donations, loans or equity investment."}'::jsonb),
('5-2-sources-of-finance:match:f41a4cf8', '5-2-sources-of-finance', '5.2 Sources of Finance', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Owner''s capital”?", "options": ["Money from the owner''s own savings invested into the business to provide start-up or development finance.", "A fixed sum of money borrowed from a bank for a stated purpose and period, repaid with interest in instalments.", "A new partner contributes capital to a partnership in exchange for a share of ownership and future profits.", "Raising finance by selling fixed assets — such as machinery, vehicles or property — that the business owns."]}'::jsonb, '{"answer": 0, "explain": "“Owner''s capital” means: Money from the owner''s own savings invested into the business to provide start-up or development finance."}'::jsonb),
('5-2-sources-of-finance:match:8cbd5e8a', '5-2-sources-of-finance', '5.2 Sources of Finance', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Bank loan”?", "options": ["A new partner contributes capital to a partnership in exchange for a share of ownership and future profits.", "Raising finance by selling fixed assets — such as machinery, vehicles or property — that the business owns.", "An asset offered to a lender as a guarantee of repayment; the lender can sell it if the loan is not repaid.", "A fixed sum of money borrowed from a bank for a stated purpose and period, repaid with interest in instalments."]}'::jsonb, '{"answer": 3, "explain": "“Bank loan” means: A fixed sum of money borrowed from a bank for a stated purpose and period, repaid with interest in instalments."}'::jsonb),
('5-2-sources-of-finance:match:5cbce412', '5-2-sources-of-finance', '5.2 Sources of Finance', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Taking on a new partner”?", "options": ["Raising finance by selling fixed assets — such as machinery, vehicles or property — that the business owns.", "An asset offered to a lender as a guarantee of repayment; the lender can sell it if the loan is not repaid.", "A payment made to shareholders from a company''s profits as a return on their investment.", "A new partner contributes capital to a partnership in exchange for a share of ownership and future profits."]}'::jsonb, '{"answer": 3, "explain": "“Taking on a new partner” means: A new partner contributes capital to a partnership in exchange for a share of ownership and future profits."}'::jsonb),
('5-2-sources-of-finance:match:5def71fa', '5-2-sources-of-finance', '5.2 Sources of Finance', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Sale of assets”?", "options": ["An asset offered to a lender as a guarantee of repayment; the lender can sell it if the loan is not repaid.", "A payment made to shareholders from a company''s profits as a return on their investment.", "Raising finance by selling fixed assets — such as machinery, vehicles or property — that the business owns.", "Money raised from within the business itself, such as owner''s capital, retained profit or sale of assets."]}'::jsonb, '{"answer": 2, "explain": "“Sale of assets” means: Raising finance by selling fixed assets — such as machinery, vehicles or property — that the business owns."}'::jsonb),
('5-2-sources-of-finance:match:10d4fad3', '5-2-sources-of-finance', '5.2 Sources of Finance', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Security”?", "options": ["A payment made to shareholders from a company''s profits as a return on their investment.", "An asset offered to a lender as a guarantee of repayment; the lender can sell it if the loan is not repaid.", "Money raised from within the business itself, such as owner''s capital, retained profit or sale of assets.", "Money raised from outside the business, such as loans, overdrafts, share issues, trade credit or crowdfunding."]}'::jsonb, '{"answer": 1, "explain": "“Security” means: An asset offered to a lender as a guarantee of repayment; the lender can sell it if the loan is not repaid."}'::jsonb),
('5-2-sources-of-finance:match:824d5c53', '5-2-sources-of-finance', '5.2 Sources of Finance', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Dividend”?", "options": ["A payment made to shareholders from a company''s profits as a return on their investment.", "Money raised from within the business itself, such as owner''s capital, retained profit or sale of assets.", "Money raised from outside the business, such as loans, overdrafts, share issues, trade credit or crowdfunding.", "Profit that is not distributed to shareholders as a dividend but is reinvested back into the business."]}'::jsonb, '{"answer": 0, "explain": "“Dividend” means: A payment made to shareholders from a company''s profits as a return on their investment."}'::jsonb),
('5-2-sources-of-finance:match:6047bd23', '5-2-sources-of-finance', '5.2 Sources of Finance', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Internal finance”?", "options": ["Money raised from outside the business, such as loans, overdrafts, share issues, trade credit or crowdfunding.", "Profit that is not distributed to shareholders as a dividend but is reinvested back into the business.", "Money raised from within the business itself, such as owner''s capital, retained profit or sale of assets.", "An arrangement with a bank that allows a business to spend more money than it has in its current account, up to an agreed limit."]}'::jsonb, '{"answer": 2, "explain": "“Internal finance” means: Money raised from within the business itself, such as owner''s capital, retained profit or sale of assets."}'::jsonb),
('5-2-sources-of-finance:match:3dd702f5', '5-2-sources-of-finance', '5.2 Sources of Finance', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “External finance”?", "options": ["Money raised from outside the business, such as loans, overdrafts, share issues, trade credit or crowdfunding.", "Profit that is not distributed to shareholders as a dividend but is reinvested back into the business.", "An arrangement with a bank that allows a business to spend more money than it has in its current account, up to an agreed limit.", "An arrangement where a business obtains goods from a supplier without making immediate payment, typically repaying within 30–90 days."]}'::jsonb, '{"answer": 0, "explain": "“External finance” means: Money raised from outside the business, such as loans, overdrafts, share issues, trade credit or crowdfunding."}'::jsonb),
('5-3-revenue-costs-profit-loss:exam:fb508a68', '5-3-revenue-costs-profit-loss', '5.3 Revenue, Costs, Profit', 'exam', 'mcq', 1, '{"num": "Q1", "question": "The business made a net profit of: [1 mark]", "options": ["£3 million", "£16.5 million", "£1636.5 million", "£1650 million"], "caseStudy": "In 2023 a business sold 22 million items at an average price of £0.75 per item. Its total costs for the year were £13.5 million.", "hint": "First calculate revenue (quantity × price), then subtract total costs to find profit.", "starter": "Revenue = quantity × price, so the net profit is..."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\"><h5>Answer: A — £3 million</h5><ul><li><strong>Working:</strong> Revenue = 22m × £0.75 = £16.5m. Net profit = £16.5m − £13.5m = £3m.</li><li><strong>Why B is wrong:</strong> £16.5m is the revenue figure, not the profit — costs have not been subtracted.</li><li><strong>Why C is wrong:</strong> No valid calculation produces this figure — a common error from multiplying rather than subtracting.</li><li><strong>Why D is wrong:</strong> £1,650m incorrectly treats both figures as millions and adds them rather than subtracting.</li></ul></div>", "modelAnswer": "Revenue = 22 million × £0.75 = £16.5 million. Net profit = Revenue − Total Costs = £16.5m − £13.5m = £3 million. Answer: A."}'::jsonb),
('5-3-revenue-costs-profit-loss:exam:4c28f093', '5-3-revenue-costs-profit-loss', '5.3 Revenue, Costs, Profit', 'exam', 'mcq', 1, '{"num": "Q2", "question": "Which would be variable costs for a building firm? [1 mark]", "options": ["Administrative and legal expenses", "Bricks and roof tiles", "Business rates and buildings insurance", "Cement mixers and tools"], "hint": "Variable costs change with output — think about what the building firm uses MORE of when it builds more houses.", "starter": "Variable costs change when output changes, so the answer is..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\"><h5>Answer: B — Bricks and roof tiles</h5><ul><li><strong>Why B is correct:</strong> Bricks and roof tiles are raw materials — the more buildings the firm constructs, the more materials it uses. They change directly with output.</li><li><strong>Why A is wrong:</strong> Administrative and legal expenses are largely fixed — they don''t change significantly with the number of buildings constructed.</li><li><strong>Why C is wrong:</strong> Business rates and buildings insurance are fixed costs — paid regardless of output.</li><li><strong>Why D is wrong:</strong> Cement mixers and tools are capital equipment — a one-off fixed cost, not a variable cost.</li></ul></div>", "modelAnswer": "B — Bricks and roof tiles. These are raw materials that the firm uses more of when it builds more — a classic variable cost. Answer: B."}'::jsonb),
('5-3-revenue-costs-profit-loss:exam:8b9d0010', '5-3-revenue-costs-profit-loss', '5.3 Revenue, Costs, Profit', 'exam', 'mcq', 1, '{"num": "Q3", "question": "This means that: [1 mark]", "options": ["every £100 of sales earns £1.30 less net profit than it used to", "for every £100 of sales the company only earns £1.30", "net profit levels have fallen by 1.3%", "the company has made a net loss of 1.3%"], "caseStudy": "A company has recently experienced a fall in its net profit margin from 4.2% to 2.9%.", "hint": "A net profit margin of 4.2% means £4.20 per £100 of sales. A margin of 2.9% means £2.90 per £100. What is the difference?", "starter": "A net profit margin of 4.2% means £4.20 per £100 of sales, so the fall means..."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\"><h5>Answer: A — every £100 of sales earns £1.30 less net profit than it used to</h5><ul><li><strong>Why A is correct:</strong> 4.2% means £4.20 per £100. 2.9% means £2.90 per £100. The difference is £1.30 per £100 of sales.</li><li><strong>Why B is wrong:</strong> The company earns £2.90 per £100 (the current margin), not £1.30. B confuses the margin difference with the current margin.</li><li><strong>Why C is wrong:</strong> Net profit LEVELS (the £ amount) have not necessarily fallen by 1.3% — the MARGIN has fallen by 1.3 percentage points. These are different things.</li><li><strong>Why D is wrong:</strong> A margin of 2.9% still means a positive profit. The company is less profitable but is NOT making a loss.</li></ul><p><strong>Examiner''s Comment:</strong> This was the least well-answered question in the paper. Many students chose C, confusing a fall in the margin with a fall in the actual profit level.</p></div>", "modelAnswer": "Net profit margin of 4.2% = £4.20 per £100 of sales. Net profit margin of 2.9% = £2.90 per £100. Difference = £1.30 less per £100. The company earns £1.30 less net profit for every £100 of sales. Answer: A."}'::jsonb),
('5-3-revenue-costs-profit-loss:exam:ff86fcde', '5-3-revenue-costs-profit-loss', '5.3 Revenue, Costs, Profit', 'exam', 'mcq', 1, '{"num": "Q4", "question": "The percentage change in the company''s total costs from 2020 to 2023 was: [1 mark]", "options": ["33%", "37.5%", "50%", "60%"], "caseStudy": "The table below shows a company''s total costs over the last four years.<table class=\"case-table\"><caption>Company Total Costs 2020–2023</caption><thead><tr><th></th><th>2020</th><th>2021</th><th>2022</th><th>2023</th></tr></thead><tbody><tr><td>Operating costs</td><td>£200,000</td><td>£170,000</td><td>£280,000</td><td>£320,000</td></tr><tr><td>Other costs</td><td>£40,000</td><td>£30,000</td><td>£30,000</td><td>£40,000</td></tr></tbody></table>", "hint": "First calculate total costs in 2020 and 2023 by adding operating + other costs. Then use the percentage change formula: (change ÷ original) × 100.", "starter": "Total costs in 2020 = ..., total costs in 2023 = ..., so the percentage change is..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\"><h5>Answer: C — 50%</h5><ul><li><strong>Working:</strong> 2020 total = £200,000 + £40,000 = £240,000. 2023 total = £320,000 + £40,000 = £360,000. Change = £120,000. % change = (£120,000 ÷ £240,000) × 100 = 50%.</li><li><strong>Why A is wrong:</strong> 33% comes from dividing the change by the wrong denominator.</li><li><strong>Why B is wrong:</strong> 37.5% may come from comparing operating costs alone or using incorrect figures.</li><li><strong>Why D is wrong:</strong> 60% is produced by dividing by the new (2023) total rather than the original (2020) total — always use the original as the denominator.</li></ul></div>", "modelAnswer": "2020: £200,000 + £40,000 = £240,000. 2023: £320,000 + £40,000 = £360,000. Change = £120,000. % change = (£120,000 ÷ £240,000) × 100 = 50%. Answer: C."}'::jsonb),
('5-3-revenue-costs-profit-loss:exam:21e2d70e', '5-3-revenue-costs-profit-loss', '5.3 Revenue, Costs, Profit', 'exam', 'mcq', 1, '{"num": "Q5", "question": "The market trader''s gross profit margin was approximately: [1 mark]", "options": ["37%", "63%", "79%", "172%"], "caseStudy": "A market trader paid £4,600 for goods which they sold for £12,500.", "hint": "First calculate gross profit (selling price minus cost price), then express it as a percentage of the selling price (revenue).", "starter": "Gross profit = £12,500 − £4,600 = ..., then GPM = (gross profit ÷ revenue) × 100 = ..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\"><h5>Answer: B — 63%</h5><ul><li><strong>Working:</strong> Gross profit = £12,500 − £4,600 = £7,900. GPM = (£7,900 ÷ £12,500) × 100 = 63.2% ≈ 63%.</li><li><strong>Why A is wrong:</strong> 37% is the cost of sales as a percentage of revenue (£4,600 ÷ £12,500), not the gross profit margin.</li><li><strong>Why C is wrong:</strong> 79% incorrectly divides gross profit by cost of sales instead of revenue.</li><li><strong>Why D is wrong:</strong> 172% is produced by dividing selling price by cost, which is not a margin calculation.</li></ul><p><strong>Examiner''s Comment:</strong> Under 40% of candidates got this right. The most common mistake was not calculating gross profit first, and just dividing figures directly.</p></div>", "modelAnswer": "Gross profit = £12,500 − £4,600 = £7,900. GPM = (£7,900 ÷ £12,500) × 100 = 63.2% ≈ 63%. Answer: B."}'::jsonb),
('5-3-revenue-costs-profit-loss:exam:1b86b277', '5-3-revenue-costs-profit-loss', '5.3 Revenue, Costs, Profit', 'exam', 'mcq', 1, '{"num": "Q6", "question": "Over the first three years of trading, the entrepreneur should expect to make: [1 mark]", "options": ["average profits of £45,000 per year", "average profits of £135,000 per year", "profits totalling £15,000", "profits totalling £45,000"], "caseStudy": "An entrepreneur has invested £150,000 to start up their own business. Their expected average rate of return is 10% per annum for the first three years.", "hint": "ARR = (Average Annual Profit ÷ Cost of Investment) × 100. Rearrange to find average annual profit, then multiply by 3 years for the total.", "starter": "If ARR is 10% and the investment is £150,000, then average annual profit = ..., and over 3 years..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\"><h5>Answer: D — profits totalling £45,000</h5><ul><li><strong>Working:</strong> ARR 10% of £150,000 = £15,000 average profit per year. Over 3 years: £15,000 × 3 = £45,000 total profit.</li><li><strong>Why A is wrong:</strong> £45,000 per year would be the total profit spread wrongly — that would imply an ARR of 30% per year, not 10%.</li><li><strong>Why B is wrong:</strong> £135,000 per year represents 90% ARR — far too high and comes from multiplying the investment by the years and the rate incorrectly.</li><li><strong>Why C is wrong:</strong> £15,000 is the average ANNUAL profit, not the total profit over 3 years.</li></ul><p><strong>Examiner''s Comment:</strong> Only half of candidates identified D. Many chose A, suggesting they did not read carefully — £45,000 is the total over 3 years, not per year.</p></div>", "modelAnswer": "Average annual profit = 10% × £150,000 = £15,000 per year. Total over 3 years = 3 × £15,000 = £45,000. Answer: D."}'::jsonb),
('5-3-revenue-costs-profit-loss:exam:3aeae4a6', '5-3-revenue-costs-profit-loss', '5.3 Revenue, Costs, Profit', 'exam', 'mcq', 1, '{"num": "Q9", "question": "Which of the following would be fixed costs of a fruit farm? [1 mark]", "options": ["Farm workers'' wages", "Plant food and fertiliser", "Rent and rates", "Seeds and seedlings"], "hint": "Fixed costs don''t change with how much fruit is grown. Which of these stays the same regardless of harvest size?", "starter": "Fixed costs stay the same regardless of output, so the answer is..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\"><h5>Answer: C — Rent and rates</h5><ul><li><strong>Why C is correct:</strong> Rent and rates are paid regardless of how much fruit is grown. They are fixed costs.</li><li><strong>Why A is wrong:</strong> Farm workers'' wages are variable — more workers (or more hours) are needed during harvest seasons when output is higher.</li><li><strong>Why B is wrong:</strong> Plant food and fertiliser change with the amount of crop being grown — a variable cost.</li><li><strong>Why D is wrong:</strong> Seeds and seedlings are variable — more seeds are used when planting more crops.</li></ul></div>", "modelAnswer": "C — Rent and rates. These are paid regardless of the size of the harvest, making them fixed costs. Answer: C."}'::jsonb),
('5-3-revenue-costs-profit-loss:exam:fc9af4e5', '5-3-revenue-costs-profit-loss', '5.3 Revenue, Costs, Profit', 'exam', 'mcq', 1, '{"num": "Q10", "question": "The entrepreneur''s average rate of return is: [1 mark]", "options": ["6.6%", "26.5%", "73.5%", "106%"], "caseStudy": "Four years ago an entrepreneur invested £200,000 to start up their own business. The business is making an average profit of £53,000 per year.", "hint": "ARR = (Average Annual Profit ÷ Cost of Investment) × 100. You already have the average annual profit — just plug it in.", "starter": "ARR = (£53,000 ÷ £200,000) × 100 = ..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\"><h5>Answer: B — 26.5%</h5><ul><li><strong>Working:</strong> ARR = (£53,000 ÷ £200,000) × 100 = 26.5%.</li><li><strong>Why A is wrong:</strong> 6.6% would come from incorrectly dividing £200,000 by £53,000 × something.</li><li><strong>Why C is wrong:</strong> 73.5% incorrectly calculates the proportion of investment NOT returned (100% − 26.5%).</li><li><strong>Why D is wrong:</strong> 106% would mean the total profit over all years exceeded the original investment, not the annual average rate.</li></ul></div>", "modelAnswer": "ARR = (Average Annual Profit ÷ Cost of Investment) × 100 = (£53,000 ÷ £200,000) × 100 = 26.5%. Answer: B."}'::jsonb),
('5-3-revenue-costs-profit-loss:exam:9a8f387a', '5-3-revenue-costs-profit-loss', '5.3 Revenue, Costs, Profit', 'exam', 'mcq', 1, '{"num": "Q11", "question": "Which of the following would help Emma and Henry deal with this problem? [1 mark]", "options": ["Holding larger stocks of raw materials", "Increasing the labourers'' wages", "Issuing shares", "Taking on a new partner"], "caseStudy": "Emma and Henry are in a partnership that runs a small building firm. Despite being profitable, the business is having difficulty paying all its expenses.", "hint": "The problem is paying expenses (a cash flow problem), not a profit problem. Which option injects cash into the business without increasing costs?", "starter": "To help with paying expenses, the business needs more funds, so..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\"><h5>Answer: D — Taking on a new partner</h5><ul><li><strong>Why D is correct:</strong> A new partner brings capital (money) into the business, which directly addresses the problem of not being able to pay expenses.</li><li><strong>Why A is wrong:</strong> Holding larger stocks ties up cash, making the cash flow problem worse, not better.</li><li><strong>Why B is wrong:</strong> Increasing wages increases costs and makes the problem worse.</li><li><strong>Why C is wrong:</strong> A partnership cannot issue shares — only limited companies can do this.</li></ul></div>", "modelAnswer": "D — Taking on a new partner. A new partner contributes capital to the business, which provides the cash needed to pay expenses. Answer: D."}'::jsonb),
('5-3-revenue-costs-profit-loss:exam:db20b658', '5-3-revenue-costs-profit-loss', '5.3 Revenue, Costs, Profit', 'exam', 'mcq', 1, '{"num": "Q12", "question": "Pilti plc''s gross profit in 2022 was: [1 mark]", "options": ["£18 million", "£26 million", "£32 million", "£58 million"], "caseStudy": "Financial data for Pilti plc in 2022 is shown below.\n• Revenue £44 million\n• Expenses £12 million\n• Net profit £14 million", "hint": "Net profit = Gross profit − Expenses. Rearrange: Gross profit = Net profit + Expenses.", "starter": "Since Net Profit = Gross Profit − Expenses, then Gross Profit = Net Profit + Expenses = ..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\"><h5>Answer: B — £26 million</h5><ul><li><strong>Working:</strong> Net profit = Gross profit − Expenses → Gross profit = Net profit + Expenses = £14m + £12m = £26m.</li><li><strong>Why A is wrong:</strong> £18m comes from subtracting expenses from net profit rather than adding them.</li><li><strong>Why C is wrong:</strong> £32m comes from subtracting net profit from revenue (Revenue − Net profit), which is not a standard formula.</li><li><strong>Why D is wrong:</strong> £58m adds revenue and net profit, which has no financial meaning.</li></ul><p><strong>Examiner''s Comment:</strong> Less than 1 in 5 candidates got this right. The key rearrangement is: Gross Profit = Net Profit + Expenses.</p></div>", "modelAnswer": "Gross Profit = Net Profit + Expenses = £14m + £12m = £26 million. Answer: B."}'::jsonb),
('5-3-revenue-costs-profit-loss:exam:5a126c96', '5-3-revenue-costs-profit-loss', '5.3 Revenue, Costs, Profit', 'exam', 'mcq', 1, '{"num": "Q13", "question": "The lowest cost that Riley can obtain 1200 litres of cleaning fluid from one supplier is: [1 mark]", "options": ["£480", "£600", "£700", "£800"], "caseStudy": "Riley runs his own cleaning business. He wishes to keep supply costs as low as possible. The table below shows the price of cleaning fluid at four possible suppliers.<table class=\"case-table\"><caption>Cleaning Fluid Prices by Supplier</caption><thead><tr><th></th><th>Supplier 1</th><th>Supplier 2</th><th>Supplier 3</th><th>Supplier 4</th></tr></thead><tbody><tr><td>Quantity</td><td>100 litre barrels</td><td>200 litre barrels</td><td>1000 litre barrels</td><td>2000 litre barrels</td></tr><tr><td>Price</td><td>£80</td><td>£100</td><td>£600</td><td>£800</td></tr></tbody></table>", "hint": "You must get AT LEAST 1200 litres from ONE supplier only. Work out the cost of getting 1200L from each supplier.", "starter": "From one supplier, to get 1200 litres: Supplier 2 (6 × 200L barrels) = 6 × £100 = ..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\"><h5>Answer: B — £600</h5><ul><li><strong>Working:</strong> Supplier 2 sells 200L barrels at £100 each. 1200L ÷ 200L = 6 barrels. Cost = 6 × £100 = £600.</li><li><strong>Why A is wrong:</strong> £480 is not achievable from any single supplier for 1200L. Supplier 1 sells 100L at £80 = £0.80/L, but 12 × £80 = £960.</li><li><strong>Why C is wrong:</strong> £700 is not achievable from any one supplier for exactly 1200L.</li><li><strong>Why D is wrong:</strong> £800 is what Supplier 4 charges for 2000L — more expensive than Supplier 2 for 1200L.</li></ul><p><strong>Examiner''s Comment:</strong> Around half got this right. Key insight: Supplier 3 sells 1000L for £600 but that is only 1000L, not enough. Supplier 2 provides exactly 1200L for £600.</p></div>", "modelAnswer": "Supplier 2: 200L barrels at £100 each. Need 1200L = 6 barrels. Cost = 6 × £100 = £600. Answer: B."}'::jsonb),
('5-3-revenue-costs-profit-loss:exam:be4dee0d', '5-3-revenue-costs-profit-loss', '5.3 Revenue, Costs, Profit', 'exam', 'mcq', 1, '{"num": "Q14", "question": "Which of the following must be true for this business? [1 mark]", "options": ["Expenses have fallen by 50%", "Net profit has increased by 3%", "Profitability has increased by 50%", "Revenue has increased by 3%"], "caseStudy": "The net profit margin of a business has increased from 6% in 2021 to 9% in 2022.", "hint": "The margin went from 6% to 9% — that is an increase of 3 percentage points. Think about what 3 extra percentage points means as a percentage change FROM 6%.", "starter": "An increase from 6% to 9% is an increase of 3 percentage points. As a percentage change from 6%, this is..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\"><h5>Answer: C — Profitability has increased by 50%</h5><ul><li><strong>Working:</strong> Percentage change in profitability = (3 ÷ 6) × 100 = 50%. The margin increased from 6% to 9% — an increase of 50% relative to the starting margin of 6%.</li><li><strong>Why A is wrong:</strong> There is no information to say expenses have fallen. Even if they have, we cannot confirm by exactly 50%.</li><li><strong>Why B is wrong:</strong> Net profit (the £ figure) has not necessarily increased by 3%. The MARGIN has risen by 3 percentage points — the actual profit change depends on revenue levels too.</li><li><strong>Why D is wrong:</strong> Revenue could have risen, fallen, or stayed the same — we cannot determine this from margin data alone.</li></ul><p><strong>Examiner''s Comment:</strong> The least well-answered MCQ. B was the most common wrong answer — students confused ''net profit'' with ''net profit margin''.</p></div>", "modelAnswer": "Profitability increased from 6% to 9% — a change of 3 from a starting point of 6. Percentage change = (3 ÷ 6) × 100 = 50%. Answer: C."}'::jsonb),
('5-3-revenue-costs-profit-loss:exam:5f0dd896', '5-3-revenue-costs-profit-loss', '5.3 Revenue, Costs, Profit', 'exam', 'mcq', 1, '{"num": "Q15", "question": "This data is useful to Amir when making this pricing decision because it shows that: [1 mark]", "options": ["changing the price charged for each loaf will have little effect on total revenue", "charging a relatively high price for each loaf is likely to increase total revenue", "reducing the price charged for each loaf is likely to increase total revenue", "the current price should not be changed because it maximises total revenue"], "caseStudy": "Amir runs a market stall that sells bread. His most popular product, the Farmhouse Loaf, is currently priced at £2.00. Amir is considering changing the price he charges for the Farmhouse Loaf. The table below shows Amir''s expected weekly sales of the Farmhouse Loaf at various prices.<table class=\"case-table\"><caption>Farmhouse Loaf — Price vs Expected Weekly Sales</caption><thead><tr><th>Price</th><th>Expected weekly sales</th></tr></thead><tbody><tr><td>£1.50</td><td>350</td></tr><tr><td>£1.75</td><td>250</td></tr><tr><td>£2.00</td><td>150</td></tr><tr><td>£2.25</td><td>50</td></tr></tbody></table>", "hint": "Calculate total revenue at each price point (price × quantity) and see which price gives the highest revenue.", "starter": "Calculate TR at each price: £1.50×350=..., £1.75×250=..., £2.00×150=..., £2.25×50=... Which is highest?"}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\"><h5>Answer: C — reducing the price charged for each loaf is likely to increase total revenue</h5><ul><li><strong>Working:</strong> £1.50 × 350 = £525 | £1.75 × 250 = £437.50 | £2.00 × 150 = £300 | £2.25 × 50 = £112.50. The lowest price (£1.50) produces the highest revenue.</li><li><strong>Why A is wrong:</strong> The data shows clearly that price changes have a significant effect on revenue — from £525 down to £112.50.</li><li><strong>Why B is wrong:</strong> The highest price (£2.25) produces the lowest revenue of only £112.50.</li><li><strong>Why D is wrong:</strong> The current price of £2.00 gives revenue of only £300 — lower than £1.50 would deliver.</li></ul></div>", "modelAnswer": "TR at £1.50 = £525; at £1.75 = £437.50; at £2.00 = £300; at £2.25 = £112.50. The lowest price generates the highest revenue. Answer: C."}'::jsonb),
('5-3-revenue-costs-profit-loss:exam:2bbd9cc8', '5-3-revenue-costs-profit-loss', '5.3 Revenue, Costs, Profit', 'exam', 'mcq', 1, '{"num": "Q20", "question": "Pallin Ltd''s average level of profit over the last five years is: [1 mark]", "options": ["£4,000 per year", "£5,000 per year", "£6,400 per year", "£8,000 per year"], "caseStudy": "Performance data for Pallin Ltd for the last five years of trading is shown below.<table class=\"case-table\"><caption>Pallin Ltd — Annual Profit Data</caption><thead><tr><th></th><th>2017</th><th>2018</th><th>2019</th><th>2020</th><th>2021</th></tr></thead><tbody><tr><td>Profit</td><td>£15,000</td><td>£0</td><td>−£9,000</td><td>£17,000</td><td>−£3,000</td></tr></tbody></table>", "hint": "Add all five profit figures (including the negative ones/losses) and divide by 5.", "starter": "Total profit = £15,000 + £0 + (−£9,000) + £17,000 + (−£3,000) = ... ÷ 5 = ..."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\"><h5>Answer: A — £4,000 per year</h5><ul><li><strong>Working:</strong> Total = £15,000 + 0 + (−£9,000) + £17,000 + (−£3,000) = £20,000. Average = £20,000 ÷ 5 = £4,000 per year.</li><li><strong>Why B is wrong:</strong> £5,000 may come from summing only the profitable years or using incorrect figures.</li><li><strong>Why C is wrong:</strong> £6,400 may result from ignoring the loss years entirely.</li><li><strong>Why D is wrong:</strong> £8,000 comes from summing all positive figures and dividing by 2 profitable years only, rather than all 5 years.</li></ul></div>", "modelAnswer": "£15,000 + 0 − £9,000 + £17,000 − £3,000 = £20,000. Average = £20,000 ÷ 5 = £4,000 per year. Answer: A."}'::jsonb),
('5-3-revenue-costs-profit-loss:exam:0ec610bf', '5-3-revenue-costs-profit-loss', '5.3 Revenue, Costs, Profit', 'exam', 'mcq', 1, '{"num": "Q21", "question": "This means: [1 mark]", "options": ["for every £10 of sales, it makes £5 profit after all costs have been paid", "the perfume shop''s variable costs are exactly half of its fixed costs", "the shop charges customers double what it pays when buying the perfume", "to make £10 of profit, it needs to sell £50 of perfume"], "caseStudy": "A perfume shop has a gross profit margin of 50%.", "hint": "A GPM of 50% means gross profit is 50% of revenue. If selling price is double the cost price, what is the gross profit as a percentage of sales?", "starter": "GPM 50% means for every £100 of sales, £50 is gross profit and £50 is cost of sales. If cost = £50 and revenue = £100, then..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\"><h5>Answer: C — the shop charges customers double what it pays when buying the perfume</h5><ul><li><strong>Why C is correct:</strong> GPM = 50% means cost of sales = 50% of revenue. If selling price is £10 and cost of sales is £5 (50%), the shop charges double what it pays. Gross profit = £5, which is 50% of £10 revenue.</li><li><strong>Why A is wrong:</strong> GPM is gross profit — it does NOT account for all costs. After all costs, the NET profit margin applies. £5 after ALL costs would require a net profit margin of 50%.</li><li><strong>Why B is wrong:</strong> There is no relationship between GPM and the ratio of variable to fixed costs.</li><li><strong>Why D is wrong:</strong> If GPM = 50% and profit = £10, revenue needed = £10 ÷ 0.50 = £20, not £50.</li></ul><p><strong>Examiner''s Comment:</strong> This was the least well-answered question in Section A. A was the most popular wrong answer — students confused gross profit (before expenses) with net profit (after all costs).</p></div>", "modelAnswer": "GPM = 50% means cost of sales = 50% of revenue. So selling price = twice the cost price. The shop charges double what it pays for the perfume. Answer: C."}'::jsonb),
('5-3-revenue-costs-profit-loss:exam:4b8efe2d', '5-3-revenue-costs-profit-loss', '5.3 Revenue, Costs, Profit', 'exam', 'mcq', 1, '{"num": "Q22", "question": "The manufacturer''s estimated total cost for the year is: [1 mark]", "options": ["£66,840", "£77,500", "£85,900", "£86,800"], "caseStudy": "A drum kit manufacturer plans to make 500 drum kits this year. Estimated costs are as follows:\n• raw materials £40 per drum kit\n• rent £600 per month\n• heating and lighting £900 per quarter\n• other expenses £56,000 per annum", "hint": "Convert all costs to annual figures: raw materials × 500 kits; rent × 12 months; heating × 4 quarters; other expenses are already annual.", "starter": "Variable costs = 500 × £40 = ... Fixed costs: rent = £600×12 = ..., heating = £900×4 = ..., other = £56,000. Total = ..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\"><h5>Answer: D — £86,800</h5><ul><li><strong>Working:</strong> Variable: 500 × £40 = £20,000. Fixed: rent = £600 × 12 = £7,200; heating = £900 × 4 = £3,600; other = £56,000. Fixed total = £66,800. TC = £20,000 + £66,800 = £86,800.</li><li><strong>Why A is wrong:</strong> £66,840 might come from using only part of the fixed costs or miscalculating heating/rent periods.</li><li><strong>Why B is wrong:</strong> £77,500 comes from miscalculating one or more of the cost components.</li><li><strong>Why C is wrong:</strong> £85,900 may come from a small arithmetic error in one category.</li></ul></div>", "modelAnswer": "VC = 500 × £40 = £20,000. Rent = £600 × 12 = £7,200. Heating = £900 × 4 = £3,600. Other = £56,000. TC = £20,000 + £7,200 + £3,600 + £56,000 = £86,800. Answer: D."}'::jsonb),
('5-3-revenue-costs-profit-loss:exam:354ca3f5', '5-3-revenue-costs-profit-loss', '5.3 Revenue, Costs, Profit', 'exam', 'mcq', 1, '{"num": "Q23", "question": "Which of the following would be a variable cost for a restaurant? [1 mark]", "options": ["Advertising fees", "Buildings insurance", "Chef''s salary", "Fruit and vegetables"], "hint": "Variable costs change with how much the restaurant produces (serves). Which item changes with the number of meals prepared?", "starter": "Variable costs change with output. The more meals served, the more... is needed."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\"><h5>Answer: D — Fruit and vegetables</h5><ul><li><strong>Why D is correct:</strong> Fruit and vegetables are raw materials (ingredients). The more meals served, the more ingredients are needed — a classic variable cost.</li><li><strong>Why A is wrong:</strong> Advertising fees are typically fixed (contracted or decided in advance) — they don''t change with the number of meals served.</li><li><strong>Why B is wrong:</strong> Buildings insurance is a fixed cost — it doesn''t change with output.</li><li><strong>Why C is wrong:</strong> The chef''s salary is a fixed annual payment — not variable. (If the chef were paid per meal cooked, it would be variable.)</li></ul></div>", "modelAnswer": "D — Fruit and vegetables are ingredients (raw materials). The more meals the restaurant serves, the more ingredients are needed. Answer: D."}'::jsonb),
('5-3-revenue-costs-profit-loss:exam:3e60f4b8', '5-3-revenue-costs-profit-loss', '5.3 Revenue, Costs, Profit', 'exam', 'mcq', 1, '{"num": "Q24", "question": "Tictal Ltd''s gross profit margin in 2020 was: [1 mark]", "options": ["25%", "45%", "55%", "75%"], "caseStudy": "Financial data for Tictal Ltd in 2020 is shown below.\n\nRevenue £180,000\nCost of sales £45,000\nExpenses £36,000", "hint": "First calculate gross profit (Revenue − Cost of Sales), then divide by Revenue and multiply by 100.", "starter": "Gross profit = £180,000 − £45,000 = ..., GPM = (... ÷ £180,000) × 100 = ..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\"><h5>Answer: D — 75%</h5><ul><li><strong>Working:</strong> Gross profit = £180,000 − £45,000 = £135,000. GPM = (£135,000 ÷ £180,000) × 100 = 75%.</li><li><strong>Why A is wrong:</strong> 25% is the cost of sales as a percentage of revenue (£45,000 ÷ £180,000 × 100), not the gross profit margin.</li><li><strong>Why B is wrong:</strong> 45% may come from incorrectly using net profit (revenue − cost of sales − expenses) and dividing by a wrong figure.</li><li><strong>Why C is wrong:</strong> 55% may come from subtracting both cost of sales and expenses from revenue before calculating the margin.</li></ul></div>", "modelAnswer": "Gross profit = £180,000 − £45,000 = £135,000. GPM = (£135,000 ÷ £180,000) × 100 = 75%. Answer: D."}'::jsonb),
('5-3-revenue-costs-profit-loss:exam:e60bc429', '5-3-revenue-costs-profit-loss', '5.3 Revenue, Costs, Profit', 'exam', 'mcq', 1, '{"num": "Q25", "question": "Assuming the forecasted figures are correct, the average rate of return for this upgrade will be: [1 mark]", "options": ["33%", "50%", "67%", "100%"], "caseStudy": "An advertising agency wishes to upgrade its design software at a cost of £60,000. The net cash flow generated by the software for each of the next two years is forecast to be £60,000.", "hint": "Step 1: Total income = 2 × £60,000. Step 2: Total profit = Total income − Cost of investment. Step 3: Average annual profit ÷ cost of investment × 100.", "starter": "Total income = 2 × £60,000 = ... Total profit = ... − £60,000 = ... Average annual profit = ... ÷ 2 = ... ARR = (... ÷ £60,000) × 100 = ..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\"><h5>Answer: B — 50%</h5><ul><li><strong>Working:</strong> Total income = 2 × £60,000 = £120,000. Total profit = £120,000 − £60,000 = £60,000. Average annual profit = £60,000 ÷ 2 = £30,000. ARR = (£30,000 ÷ £60,000) × 100 = 50%.</li><li><strong>Why A is wrong:</strong> 33% may come from dividing by 3 years incorrectly.</li><li><strong>Why C is wrong:</strong> 67% may come from miscalculating the profit or average.</li><li><strong>Why D is wrong:</strong> 100% would come from ignoring Step 1 (not subtracting cost) and just dividing total income by cost.</li></ul></div>", "modelAnswer": "Total income = £120,000. Profit = £120,000 − £60,000 = £60,000. Average annual = £30,000. ARR = (£30,000 ÷ £60,000) × 100 = 50%. Answer: B."}'::jsonb),
('5-3-revenue-costs-profit-loss:exam:c54020b7', '5-3-revenue-costs-profit-loss', '5.3 Revenue, Costs, Profit', 'exam', 'mcq', 1, '{"num": "Q27", "question": "What percentage reduction in transport costs has Shanco plc achieved? [1 mark]", "options": ["6%", "7%", "14.3%", "16.7%"], "caseStudy": "Shanco plc has managed to reduce its transport costs from £0.7 million in 2019 to £0.6 million in 2020.", "hint": "Percentage change = (Change ÷ Original) × 100. The original is the 2019 figure.", "starter": "Change = £0.7m − £0.6m = £0.1m. % reduction = (£0.1m ÷ £0.7m) × 100 = ..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\"><h5>Answer: C — 14.3%</h5><ul><li><strong>Working:</strong> Change = £0.7m − £0.6m = £0.1m. % change = (£0.1m ÷ £0.7m) × 100 = 14.3%.</li><li><strong>Why A is wrong:</strong> 6% has no clear derivation from the given figures.</li><li><strong>Why B is wrong:</strong> 7% is not achieved by any correct method.</li><li><strong>Why D is wrong:</strong> 16.7% comes from dividing by the NEW value (£0.6m) instead of the ORIGINAL value (£0.7m) — always use the original as the denominator.</li></ul></div>", "modelAnswer": "Change = £0.1m. % reduction = (£0.1m ÷ £0.7m) × 100 = 14.3%. Answer: C."}'::jsonb),
('5-3-revenue-costs-profit-loss:exam:5467638c', '5-3-revenue-costs-profit-loss', '5.3 Revenue, Costs, Profit', 'exam', 'mcq', 1, '{"num": "Q29", "question": "The company''s labour costs in 2019 were: [1 mark]", "options": ["£3.6 million", "£5.4 million", "£12.6 million", "£14.4 million"], "caseStudy": "A company''s total costs in 2019 were £9 million. The company''s labour costs were 40% of the company''s total costs.", "hint": "Labour costs = 40% of total costs. Calculate 40% of £9 million.", "starter": "Labour costs = 40% × £9 million = ..."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\"><h5>Answer: A — £3.6 million</h5><ul><li><strong>Working:</strong> 40% × £9m = 0.40 × £9m = £3.6 million.</li><li><strong>Why B is wrong:</strong> £5.4m is 60% of £9m — the proportion that is NOT labour costs.</li><li><strong>Why C is wrong:</strong> £12.6m incorrectly adds 40% to £9m instead of finding 40% of £9m.</li><li><strong>Why D is wrong:</strong> £14.4m comes from multiplying £9m by 1.6 rather than 0.4.</li></ul></div>", "modelAnswer": "Labour costs = 40% × £9m = £3.6 million. Answer: A."}'::jsonb),
('5-3-revenue-costs-profit-loss:exam:175e2e65', '5-3-revenue-costs-profit-loss', '5.3 Revenue, Costs, Profit', 'exam', 'mcq', 1, '{"num": "Q30", "question": "Variable costs: [1 mark]", "options": ["are not affected by changes in output", "fall as output rises", "increase as output rises", "remain constant over time"], "hint": "Think about what happens to a manufacturer''s raw material costs when they produce twice as many products.", "starter": "Variable costs are costs that... as output changes."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\"><h5>Answer: C — increase as output rises</h5><ul><li><strong>Why C is correct:</strong> Variable costs (e.g. raw materials, packaging) increase directly as more is produced — more output requires more inputs.</li><li><strong>Why A is wrong:</strong> That describes fixed costs, not variable costs.</li><li><strong>Why B is wrong:</strong> Variable costs do not fall as output rises — they increase.</li><li><strong>Why D is wrong:</strong> Remaining constant describes fixed costs.</li></ul></div>", "modelAnswer": "C — Variable costs increase as output rises. As more products are made, more raw materials, packaging and labour are needed. Answer: C."}'::jsonb),
('5-3-revenue-costs-profit-loss:exam:1ae8eeb8', '5-3-revenue-costs-profit-loss', '5.3 Revenue, Costs, Profit', 'exam', 'mcq', 1, '{"num": "Q31", "question": "The expected average rate of return for this purchase is: [1 mark]", "options": ["£1,000", "£3,000", "16.67%", "33.33%"], "caseStudy": "A furniture maker intends to purchase a new wood cutting machine. The expected cost and incomes generated by the machine for the next three years are shown in the table below.<table class=\"case-table\"><caption>Wood Cutting Machine — Expected Costs and Income</caption><thead><tr><th></th><th>Amount</th></tr></thead><tbody><tr><td>Cost of machine</td><td>£6,000</td></tr><tr><td>Income year 1</td><td>£3,000</td></tr><tr><td>Income year 2</td><td>£3,000</td></tr><tr><td>Income year 3</td><td>£3,000</td></tr></tbody></table>", "hint": "Step 1: Total income = £9,000. Total profit = £9,000 − £6,000 = £3,000. Step 2: Average annual profit = £3,000 ÷ 3. Step 3: ARR = (average annual profit ÷ £6,000) × 100.", "starter": "Total profit = £9,000 − £6,000 = £3,000. Average annual profit = £3,000 ÷ 3 = £1,000. ARR = (£1,000 ÷ £6,000) × 100 = ..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\"><h5>Answer: C — 16.67%</h5><ul><li><strong>Working:</strong> Total income = £9,000. Total profit = £9,000 − £6,000 = £3,000. Average annual profit = £3,000 ÷ 3 = £1,000. ARR = (£1,000 ÷ £6,000) × 100 = 16.67%.</li><li><strong>Why A is wrong:</strong> £1,000 is the average annual profit — the number used IN the ARR calculation, not the ARR itself.</li><li><strong>Why B is wrong:</strong> £3,000 is total profit, not ARR.</li><li><strong>Why D is wrong:</strong> 33.33% comes from dividing total profit by cost (£3,000 ÷ £6,000 × 100) — skipping Step 2 (averaging over the years).</li></ul></div>", "modelAnswer": "Profit = £9,000 − £6,000 = £3,000. Average annual = £1,000. ARR = (£1,000 ÷ £6,000) × 100 = 16.67%. Answer: C."}'::jsonb),
('5-3-revenue-costs-profit-loss:exam:b5c6810f', '5-3-revenue-costs-profit-loss', '5.3 Revenue, Costs, Profit', 'exam', 'mcq', 1, '{"num": "Q33", "question": "If Andrea paints and sells 50 portraits a year, total costs are estimated to be: [1 mark]", "options": ["£1,075 per year", "£4,750 per year", "£12,075 per year", "£15,750 per year"], "caseStudy": "Andrea specialises in painting portraits. She estimates that:\n• variable costs for labour are £52 per portrait\n• variable costs for materials are £23 per portrait\n• fixed costs are £1,000 per month", "hint": "Variable cost per portrait = £52 + £23 = £75. Total variable costs = 50 × £75. Fixed costs = £1,000 × 12 months. Add both.", "starter": "VC per portrait = £52 + £23 = £75. TVC = 50 × £75 = ... Fixed costs = £1,000 × 12 = ... TC = ..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\"><h5>Answer: D — £15,750 per year</h5><ul><li><strong>Working:</strong> VC per portrait = £52 + £23 = £75. TVC = 50 × £75 = £3,750. Fixed costs = £1,000 × 12 months = £12,000. TC = £3,750 + £12,000 = £15,750.</li><li><strong>Why A is wrong:</strong> £1,075 ignores most costs — possibly just adding £52 + £23 = £75 then adding £1,000 once.</li><li><strong>Why B is wrong:</strong> £4,750 is the variable costs only (£3,750) plus one month''s fixed costs (£1,000).</li><li><strong>Why C is wrong:</strong> £12,075 is the annual fixed costs (£12,000) plus only one portrait''s variable costs (£75).</li></ul></div>", "modelAnswer": "VC = 50 × (£52 + £23) = 50 × £75 = £3,750. FC = £1,000 × 12 = £12,000. TC = £3,750 + £12,000 = £15,750. Answer: D."}'::jsonb),
('5-3-revenue-costs-profit-loss:exam:bd129f1c', '5-3-revenue-costs-profit-loss', '5.3 Revenue, Costs, Profit', 'exam', 'mcq', 1, '{"num": "Q34", "question": "This data is useful to Seiji when making business decisions because it shows that: [1 mark]", "options": ["labour costs are increasing every year", "profit levels are falling", "the business is producing less than it used to", "total costs are increasing"], "caseStudy": "Seiji, a sole trader, has some important decisions to make about his business. He has produced a table showing the costs of running his business over the last four years.<table class=\"case-table\"><caption>Seiji''s Business Costs 2015–2018</caption><thead><tr><th></th><th>2015</th><th>2016</th><th>2017</th><th>2018</th></tr></thead><tbody><tr><td>Labour costs</td><td>£44,000</td><td>£66,000</td><td>£65,000</td><td>£62,000</td></tr><tr><td>Raw material costs</td><td>£36,000</td><td>£35,000</td><td>£34,000</td><td>£33,000</td></tr><tr><td>Other costs</td><td>£18,000</td><td>£25,000</td><td>£32,000</td><td>£39,000</td></tr></tbody></table>", "hint": "Add up all three cost rows for each year and compare. Which statement can definitely be proven from this data?", "starter": "Total costs: 2015 = £98,000; 2016 = ...; 2017 = ...; 2018 = ... The trend is..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\"><h5>Answer: D — total costs are increasing</h5><ul><li><strong>Working:</strong> 2015: £98,000. 2016: £126,000. 2017: £131,000. 2018: £134,000. Total costs are clearly rising year on year.</li><li><strong>Why A is wrong:</strong> Labour costs are NOT increasing every year — they rose from 2015 to 2016 but then fell in 2017 and 2018.</li><li><strong>Why B is wrong:</strong> We have no revenue data, so we cannot determine whether profit levels are falling.</li><li><strong>Why C is wrong:</strong> We cannot determine output levels from cost data alone.</li></ul></div>", "modelAnswer": "Total costs: 2015=£98,000; 2016=£126,000; 2017=£131,000; 2018=£134,000 — consistently rising. Answer: D."}'::jsonb),
('5-3-revenue-costs-profit-loss:exam:182cd390', '5-3-revenue-costs-profit-loss', '5.3 Revenue, Costs, Profit', 'exam', 'mcq', 1, '{"num": "Q35", "question": "Assuming the forecasted figures are correct, the average rate of return for upgrading the robotics will be: [1 mark]", "options": ["5%", "20%", "25%", "125%"], "caseStudy": "A tractor manufacturer wishes to upgrade its robotics at a total cost of £4 million. The cash inflow for each of the next five years is forecasted to be £1 million.", "hint": "Step 1: Total income = 5 × £1m. Total profit = total income − cost. Step 2: Average annual profit ÷ 5. Step 3: ARR = (average annual profit ÷ £4m) × 100.", "starter": "Total income = £5m. Profit = £5m − £4m = £1m. Average annual profit = £1m ÷ 5 = £0.2m. ARR = (£0.2m ÷ £4m) × 100 = ..."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\"><h5>Answer: A — 5%</h5><ul><li><strong>Working:</strong> Total income = 5 × £1m = £5m. Total profit = £5m − £4m = £1m. Average annual profit = £1m ÷ 5 = £0.2m. ARR = (£0.2m ÷ £4m) × 100 = 5%.</li><li><strong>Why B is wrong:</strong> 20% skips Step 2 — dividing £1m (total profit) by £4m gives 25%, not 20%.</li><li><strong>Why C is wrong:</strong> 25% comes from dividing total profit (£1m) by cost (£4m) without dividing by years first.</li><li><strong>Why D is wrong:</strong> 125% comes from total income (£5m) ÷ cost (£4m) × 100 — ignoring the need to subtract cost first.</li></ul></div>", "modelAnswer": "Profit = £5m − £4m = £1m. Average annual = £0.2m. ARR = (£0.2m ÷ £4m) × 100 = 5%. Answer: A."}'::jsonb),
('5-3-revenue-costs-profit-loss:exam:1df18a21', '5-3-revenue-costs-profit-loss', '5.3 Revenue, Costs, Profit', 'exam', 'mcq', 1, '{"num": "Q36", "question": "The agency''s percentage increase in spending on digital communications from 2017 to 2018 was approximately equal to: [1 mark]", "options": ["48%", "52%", "110%", "210%"], "caseStudy": "A market research agency needs to constantly improve its digital communications to keep up with the competition. In 2017 it spent £250,000 on digital communication. In 2018 it spent £525,000.", "hint": "Percentage change = (Change ÷ Original) × 100. The 2017 figure is the original. The figures have more than doubled, so the answer must be over 100%.", "starter": "Change = £525,000 − £250,000 = £275,000. % change = (£275,000 ÷ £250,000) × 100 = ..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\"><h5>Answer: C — 110%</h5><ul><li><strong>Working:</strong> Change = £525,000 − £250,000 = £275,000. % change = (£275,000 ÷ £250,000) × 100 = 110%.</li><li><strong>Why A is wrong:</strong> 48% comes from dividing by the NEW value (£525,000): 275/525 × 100 ≈ 52%. Not 48%.</li><li><strong>Why B is wrong:</strong> 52% comes from (£275,000 ÷ £525,000) × 100 — using the new figure as denominator instead of the original.</li><li><strong>Why D is wrong:</strong> 210% comes from (£525,000 ÷ £250,000) × 100 — this is the new value as a % of old, not the % CHANGE.</li></ul><p><strong>Examiner''s Comment:</strong> This had the most incorrect answers of all MCQs. Key rule: always divide by the ORIGINAL value for percentage change. Since spending more than doubled, the answer must exceed 100%.</p></div>", "modelAnswer": "Change = £275,000. % change = (£275,000 ÷ £250,000) × 100 = 110%. Answer: C."}'::jsonb),
('5-3-revenue-costs-profit-loss:exam:9f050750', '5-3-revenue-costs-profit-loss', '5.3 Revenue, Costs, Profit', 'exam', 'mcq', 1, '{"num": "Q38", "question": "What was the market stall''s revenue? [1 mark]", "options": ["£200", "£1,000", "£1,200", "£2,200"], "caseStudy": "A market stall sells bread for £1 a loaf and cookies for 60p each. Yesterday 1,000 loaves of bread and 2,000 cookies were sold.", "hint": "Calculate revenue for bread and cookies separately, then add them together.", "starter": "Bread revenue = 1,000 × £1 = ... Cookie revenue = 2,000 × £0.60 = ... Total = ..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\"><h5>Answer: D — £2,200</h5><ul><li><strong>Working:</strong> Bread: 1,000 × £1 = £1,000. Cookies: 2,000 × £0.60 = £1,200. Total = £1,000 + £1,200 = £2,200.</li><li><strong>Why A is wrong:</strong> £200 is not achievable from any correct calculation with these figures.</li><li><strong>Why B is wrong:</strong> £1,000 is bread revenue only — cookies have been ignored.</li><li><strong>Why C is wrong:</strong> £1,200 is cookie revenue only — bread has been ignored.</li></ul></div>", "modelAnswer": "Bread: 1,000 × £1 = £1,000. Cookies: 2,000 × £0.60 = £1,200. Total revenue = £2,200. Answer: D."}'::jsonb),
('5-3-revenue-costs-profit-loss:exam:cb3c0ecf', '5-3-revenue-costs-profit-loss', '5.3 Revenue, Costs, Profit', 'exam', 'mcq', 1, '{"num": "Q39", "question": "Gross profit margin is: [1 mark]", "options": ["a computerised method of production", "a financial ratio", "a pricing method", "a variable cost"], "hint": "GPM measures the percentage of revenue kept as gross profit. Which category does this type of calculation belong to?", "starter": "The gross profit margin is a type of..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\"><h5>Answer: B — a financial ratio</h5><ul><li><strong>Why B is correct:</strong> GPM is a profitability ratio — a calculation that expresses one financial figure as a percentage of another (gross profit as a % of revenue).</li><li><strong>Why A is wrong:</strong> A computerised method of production is something like an automated assembly line — completely unrelated to financial performance.</li><li><strong>Why C is wrong:</strong> A pricing method (e.g. cost-plus pricing, penetration pricing) is how a business sets its selling price — not a measure of profitability.</li><li><strong>Why D is wrong:</strong> Variable costs are costs that change with output — not a financial ratio.</li></ul></div>", "modelAnswer": "B — a financial ratio. GPM = (Gross Profit ÷ Revenue) × 100. It is a profitability ratio that measures efficiency. Answer: B."}'::jsonb),
('5-3-revenue-costs-profit-loss:exam:f27b4b6f', '5-3-revenue-costs-profit-loss', '5.3 Revenue, Costs, Profit', 'exam', 'mcq', 1, '{"num": "Q40", "question": "Which one of the following must be true for this business? [1 mark]", "options": ["The business cannot pay its short term debts", "The business has made a loss", "The business has revenues that are greater than its costs", "The business is operating below its break even level"], "caseStudy": "A business has a net profit margin of 8%.", "hint": "A positive net profit margin (8%) means the business is making a profit. What does profit mean for the relationship between revenue and costs?", "starter": "A net profit margin of 8% means the business is making a profit, which means revenue is..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\"><h5>Answer: C — The business has revenues that are greater than its costs</h5><ul><li><strong>Why C is correct:</strong> Net profit margin of 8% means net profit is positive. Net Profit = Revenue − Total Costs > 0, therefore Revenue > Total Costs.</li><li><strong>Why A is wrong:</strong> Profit and cash flow are different. A profitable business can still have cash flow problems — but we cannot determine this from profit margin alone.</li><li><strong>Why B is wrong:</strong> A positive net profit margin means a profit, not a loss.</li><li><strong>Why D is wrong:</strong> If the business is above break-even, it is making a profit. An 8% NPM confirms it is above break-even.</li></ul></div>", "modelAnswer": "A net profit margin of 8% is positive — the business is making a profit. Profit = Revenue − Total Costs > 0, so revenue MUST be greater than total costs. Answer: C."}'::jsonb),
('5-3-revenue-costs-profit-loss:exam:660a7f00', '5-3-revenue-costs-profit-loss', '5.3 Revenue, Costs, Profit', 'exam', 'mcq', 1, '{"num": "Q41", "question": "What is the approximate increase between 2015 and 2016 in Jimco plc''s production costs? [1 mark]", "options": ["0.9%", "1.6%", "7.0%", "7.5%"], "caseStudy": "The production costs for Jimco plc were £21.3 million in 2015 and £22.9 million in 2016.", "hint": "% change = (change ÷ original) × 100. Change = £22.9m − £21.3m = £1.6m. Original = £21.3m.", "starter": "Change = £22.9m − £21.3m = £1.6m. % change = (£1.6m ÷ £21.3m) × 100 = ..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\"><h5>Answer: D — 7.5%</h5><ul><li><strong>Working:</strong> Change = £22.9m − £21.3m = £1.6m. % change = (£1.6m ÷ £21.3m) × 100 ≈ 7.5%.</li><li><strong>Why A is wrong:</strong> 0.9% has no logical derivation from these figures.</li><li><strong>Why B is wrong:</strong> 1.6% confuses the absolute change (£1.6m) with the percentage change — these are different things.</li><li><strong>Why C is wrong:</strong> 7.0% may come from rounding errors or using a slightly different denominator.</li></ul></div>", "modelAnswer": "Change = £1.6m. % change = (£1.6m ÷ £21.3m) × 100 ≈ 7.5%. Answer: D."}'::jsonb),
('5-3-revenue-costs-profit-loss:exam:e7104661', '5-3-revenue-costs-profit-loss', '5.3 Revenue, Costs, Profit', 'exam', 'mcq', 1, '{"num": "Q43", "question": "In 2018 Pluck and Grow Ltd made: [1 mark]", "options": ["a loss of £52,000", "a loss of £42,000", "a profit of £16,000", "a profit of £26,000"], "caseStudy": "Financial data for Pluck and Grow Ltd in 2018 is shown below.\n\nTotal revenue £68,000\nTotal labour costs £26,000\nTotal material costs £16,000\nOther costs £10,000", "hint": "Add up all three cost categories to find total costs, then subtract from revenue. If positive = profit, if negative = loss.", "starter": "Total costs = £26,000 + £16,000 + £10,000 = ... Profit/Loss = £68,000 − ... = ..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\"><h5>Answer: C — a profit of £16,000</h5><ul><li><strong>Working:</strong> Total costs = £26,000 + £16,000 + £10,000 = £52,000. Profit = £68,000 − £52,000 = £16,000.</li><li><strong>Why A is wrong:</strong> A loss of £52,000 uses total costs as the answer — forgetting to subtract from revenue.</li><li><strong>Why B is wrong:</strong> A loss of £42,000 has no logical derivation from these figures.</li><li><strong>Why D is wrong:</strong> A profit of £26,000 uses only labour costs rather than all three cost types.</li></ul></div>", "modelAnswer": "Total costs = £26,000 + £16,000 + £10,000 = £52,000. Profit = £68,000 − £52,000 = £16,000. Answer: C."}'::jsonb),
('5-3-revenue-costs-profit-loss:exam:ed12fcd3', '5-3-revenue-costs-profit-loss', '5.3 Revenue, Costs, Profit', 'exam', 'mcq', 1, '{"num": "Q44", "question": "The data shows that: [1 mark]", "options": ["the company prefers to transport its goods by air", "the company''s transport costs have fallen year on year", "GLU plc spent more than £1.25 million on transport costs in 2018", "GLU plc transports more goods by rail than by road"], "caseStudy": "The transport costs of Global Logistics United plc (GLU plc) for the last five years are shown below.<table class=\"case-table\"><caption>GLU plc — Transport Costs by Mode (£)</caption><thead><tr><th>Mode</th><th>2014</th><th>2015</th><th>2016</th><th>2017</th><th>2018</th></tr></thead><tbody><tr><td>By road</td><td>£150,000</td><td>£160,000</td><td>£170,000</td><td>£180,000</td><td>£190,000</td></tr><tr><td>By rail</td><td>£350,000</td><td>£370,000</td><td>£390,000</td><td>£410,000</td><td>£430,000</td></tr><tr><td>By air</td><td>£600,000</td><td>£620,000</td><td>£635,000</td><td>£640,000</td><td>£650,000</td></tr></tbody></table>", "hint": "Add all three transport modes for 2018 to test option C. Check the other options against the data.", "starter": "2018 total = £190,000 + £430,000 + £650,000 = ..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\"><h5>Answer: C — GLU plc spent more than £1.25 million on transport costs in 2018</h5><ul><li><strong>Working:</strong> 2018 total = £190,000 + £430,000 + £650,000 = £1,270,000 &gt; £1,250,000. ✓</li><li><strong>Why A is wrong:</strong> The data shows costs, not preference. Highest cost could mean they are forced to use air, not that they prefer it. No preference data is given.</li><li><strong>Why B is wrong:</strong> All three transport modes show rising costs year on year, not falling.</li><li><strong>Why D is wrong:</strong> The data shows the COST of transport, not the quantity of goods. Higher cost per rail doesn''t mean more goods are transported by rail.</li></ul></div>", "modelAnswer": "2018 total transport cost = £190,000 + £430,000 + £650,000 = £1,270,000, which is more than £1.25m. Answer: C."}'::jsonb)
